import { notFound } from "next/navigation";
import { db } from "@/lib/db";
import CaseStudyForm from "@/components/admin/CaseStudyForm";

interface EditCaseStudyPageProps {
  params: {
    id: string;
  };
}

export const dynamic = "force-dynamic";

export default async function EditCaseStudyPage({ params }: EditCaseStudyPageProps) {
  const caseStudy = await db.caseStudy.findUnique({
    where: { id: params.id },
  });

  if (!caseStudy) {
    notFound();
  }

  // Parse and serialize metrics & other fields
  const serialized = {
    id: caseStudy.id,
    slug: caseStudy.slug,
    client: caseStudy.client,
    title: caseStudy.title,
    category: caseStudy.category,
    service: caseStudy.service,
    timeline: caseStudy.timeline,
    industry: caseStudy.industry,
    heroImage: caseStudy.heroImage,
    challenge: caseStudy.challenge,
    solution: caseStudy.solution,
    metrics: (caseStudy.metrics as any) || [],
    results: caseStudy.results,
    featured: caseStudy.featured,
  };

  return <CaseStudyForm initialData={serialized} mode="edit" />;
}

import { NextResponse } from "next/server";
import { db } from "@/lib/db";
import { auth } from "@/auth";
import bcrypt from "bcryptjs";

export async function PUT(req: Request) {
  try {
    const session = await auth();
    if (!session || !session.user?.id) {
      return new NextResponse("Unauthorized", { status: 401 });
    }

    const userId = session.user.id;
    const body = await req.json();
    const { name, email, currentPassword, newPassword } = body;

    // Fetch the current user record
    const user = await db.user.findUnique({ where: { id: userId } });
    if (!user) {
      return NextResponse.json({ success: false, error: "User profile not found." }, { status: 444 });
    }

    const updateData: any = {};

    // Handle Name Update
    if (name && name.trim()) {
      updateData.name = name.trim();
    }

    // Handle Email Update
    if (email && email.trim() && email.trim() !== user.email) {
      const emailLower = email.trim().toLowerCase();
      // Check if email already belongs to another user
      const duplicate = await db.user.findUnique({ where: { email: emailLower } });
      if (duplicate) {
        return NextResponse.json({ success: false, error: "Email address is already in use by another account." }, { status: 400 });
      }
      updateData.email = emailLower;
    }

    // Handle Password Update
    if (newPassword) {
      if (!currentPassword) {
        return NextResponse.json({ success: false, error: "Current password is required to change password." }, { status: 400 });
      }

      // Verify old password
      const isMatch = await bcrypt.compare(currentPassword, user.password);
      if (!isMatch) {
        return NextResponse.json({ success: false, error: "Incorrect current password." }, { status: 400 });
      }

      if (newPassword.length < 6) {
        return NextResponse.json({ success: false, error: "New password must be at least 6 characters long." }, { status: 400 });
      }

      // Hash and set new password
      updateData.password = await bcrypt.hash(newPassword, 10);
    }

    // If nothing has changed
    if (Object.keys(updateData).length === 0) {
      return NextResponse.json({ success: true, message: "No changes detected." });
    }

    const updatedUser = await db.user.update({
      where: { id: userId },
      data: updateData,
    });

    return NextResponse.json({
      success: true,
      message: "Profile updated successfully.",
      user: {
        id: updatedUser.id,
        name: updatedUser.name,
        email: updatedUser.email,
        role: updatedUser.role,
      },
    });
  } catch (error: any) {
    console.error("PUT PROFILE ERROR:", error);
    return NextResponse.json({ success: false, error: "Failed to update profile settings." }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { db } from "@/lib/db";
import { auth } from "@/auth";

export async function DELETE(
  _req: Request,
  { params }: { params: { id: string } }
) {
  try {
    const session = await auth();
    if (!session || !session.user?.id) {
      return new NextResponse("Unauthorized", { status: 401 });
    }

    const targetId = params.id;
    const currentUserId = session.user.id;

    // Safeguard: Prevent self-deletion
    if (targetId === currentUserId) {
      return NextResponse.json({ success: false, error: "Access denied. You cannot revoke your own administrator account." }, { status: 403 });
    }

    const existing = await db.user.findUnique({ where: { id: targetId } });
    if (!existing) {
      return NextResponse.json({ success: false, error: "Administrator account not found." }, { status: 404 });
    }

    // Double Safeguard: Ensure we don't accidentally leave the system with ZERO users
    const adminCount = await db.user.count();
    if (adminCount <= 1) {
      return NextResponse.json({ success: false, error: "Forbidden. System must retain at least one administrator account." }, { status: 400 });
    }

    await db.user.delete({ where: { id: targetId } });

    return NextResponse.json({ success: true, message: "Administrator access revoked successfully." });
  } catch (error: any) {
    console.error("DELETE USER ERROR:", error);
    return NextResponse.json({ success: false, error: "Failed to revoke administrator access." }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { db } from "@/lib/db";
import { auth } from "@/auth";
import bcrypt from "bcryptjs";

export async function GET(_req: Request) {
  try {
    const session = await auth();
    if (!session) return new NextResponse("Unauthorized", { status: 401 });

    const users = await db.user.findMany({
      orderBy: { createdAt: "desc" },
      select: {
        id: true,
        name: true,
        email: true,
        role: true,
        createdAt: true,
      },
    });

    return NextResponse.json({ success: true, users });
  } catch (error) {
    console.error("GET USERS ERROR:", error);
    return NextResponse.json({ success: false, error: "Failed to load admin directory." }, { status: 500 });
  }
}

export async function POST(req: Request) {
  try {
    const session = await auth();
    if (!session) return new NextResponse("Unauthorized", { status: 401 });

    const body = await req.json();
    const { name, email, password } = body;

    if (!name || !email || !password) {
      return NextResponse.json({ success: false, error: "Please fill in all required fields." }, { status: 400 });
    }

    const emailLower = email.trim().toLowerCase();

    // Check if email already registered
    const existing = await db.user.findUnique({ where: { email: emailLower } });
    if (existing) {
      return NextResponse.json({ success: false, error: "An account with this email address already exists." }, { status: 400 });
    }

    if (password.length < 6) {
      return NextResponse.json({ success: false, error: "Password must be at least 6 characters long." }, { status: 400 });
    }

    // Hash password
    const hashedPassword = await bcrypt.hash(password, 10);

    // Create admin user record
    const newUser = await db.user.create({
      data: {
        name: name.trim(),
        email: emailLower,
        password: hashedPassword,
        role: "admin", // defaults to admin role
      },
      select: {
        id: true,
        name: true,
        email: true,
        role: true,
        createdAt: true,
      },
    });

    return NextResponse.json({ success: true, user: newUser }, { status: 201 });
  } catch (error) {
    console.error("POST USER ERROR:", error);
    return NextResponse.json({ success: false, error: "Failed to register new administrator account." }, { status: 500 });
  }
}

import { NextResponse } from "next/server";
import { db } from "@/lib/db";
import { auth } from "@/auth";

export async function GET(
  _req: Request,
  { params }: { params: { id: string } }
) {
  try {
    const { id } = params;

    if (!id) {
      return NextResponse.json(
        { success: false, error: "Missing case study identifier." },
        { status: 400 }
      );
    }

    // Try finding by id first, then by slug
    let caseStudy = await db.caseStudy.findUnique({
      where: { id },
    });

    if (!caseStudy) {
      caseStudy = await db.caseStudy.findUnique({
        where: { slug: id },
      });
    }

    if (!caseStudy) {
      return NextResponse.json(
        { success: false, error: "Case study not found." },
        { status: 404 }
      );
    }

    return NextResponse.json({ success: true, caseStudy });
  } catch (error: any) {
    console.error("GET CASE STUDY ERROR:", error);
    return NextResponse.json(
      { success: false, error: "Failed to fetch case study." },
      { status: 500 }
    );
  }
}

export async function PUT(
  req: Request,
  { params }: { params: { id: string } }
) {
  try {
    const session = await auth();
    if (!session) {
      return new NextResponse("Unauthorized", { status: 401 });
    }

    const { id } = params;
    if (!id) {
      return NextResponse.json(
        { success: false, error: "Missing case study ID." },
        { status: 400 }
      );
    }

    const body = await req.json();
    const {
      slug,
      client,
      title,
      category,
      service,
      timeline,
      industry,
      heroImage,
      challenge,
      solution,
      metrics,
      results,
      featured,
    } = body;

    // Verify item exists
    const existing = await db.caseStudy.findUnique({
      where: { id },
    });

    if (!existing) {
      return NextResponse.json(
        { success: false, error: "Case study not found." },
        { status: 404 }
      );
    }

    // If slug is changed, verify new slug uniqueness
    if (slug && slug !== existing.slug) {
      const slugExists = await db.caseStudy.findUnique({
        where: { slug },
      });
      if (slugExists) {
        return NextResponse.json(
          { success: false, error: "A case study with this slug already exists." },
          { status: 400 }
        );
      }
    }

    // If setting as featured, unfeature all other studies
    if (featured) {
      await db.caseStudy.updateMany({
        where: {
          NOT: { id },
          featured: true,
        },
        data: { featured: false },
      });
    }

    const updated = await db.caseStudy.update({
      where: { id },
      data: {
        slug: slug ?? existing.slug,
        client: client ?? existing.client,
        title: title ?? existing.title,
        category: category ?? existing.category,
        service: service ?? existing.service,
        timeline: timeline ?? existing.timeline,
        industry: industry ?? existing.industry,
        heroImage: heroImage ?? existing.heroImage,
        challenge: challenge ?? existing.challenge,
        solution: solution ?? existing.solution,
        metrics: metrics ?? existing.metrics,
        results: results ?? existing.results,
        featured: featured !== undefined ? !!featured : existing.featured,
      },
    });

    return NextResponse.json({ success: true, caseStudy: updated });
  } catch (error: any) {
    console.error("PUT CASE STUDY ERROR:", error);
    return NextResponse.json(
      { success: false, error: "Failed to update case study." },
      { status: 500 }
    );
  }
}

export async function DELETE(
  _req: Request,
  { params }: { params: { id: string } }
) {
  try {
    const session = await auth();
    if (!session) {
      return new NextResponse("Unauthorized", { status: 401 });
    }

    const { id } = params;

    if (!id) {
      return NextResponse.json(
        { success: false, error: "Missing case study ID." },
        { status: 400 }
      );
    }

    // Verify it exists
    const existing = await db.caseStudy.findUnique({
      where: { id },
