    if (!existing) {
      return NextResponse.json(
        { success: false, error: "Case study not found." },
        { status: 404 }
      );
    }

    await db.caseStudy.delete({
      where: { id },
    });

    return NextResponse.json({ success: true, message: "Case study deleted successfully." });
  } catch (error: any) {
    console.error("DELETE CASE STUDY ERROR:", error);
    return NextResponse.json(
      { success: false, error: "Failed to delete case study." },
      { status: 500 }
    );
  }
}

import { NextResponse } from "next/server";
import { db } from "@/lib/db";
import { auth } from "@/auth";

export async function GET(req: Request) {
  try {
    const { searchParams } = new URL(req.url);
    const category = searchParams.get("category");
    const featured = searchParams.get("featured");

    const where: any = {};
    if (category && category !== "All") {
      where.category = category;
    }
    if (featured === "true") {
      where.featured = true;
    }

    const caseStudies = await db.caseStudy.findMany({
      where,
      orderBy: { createdAt: "desc" },
    });

    return NextResponse.json({ success: true, caseStudies });
  } catch (error: any) {
    console.error("GET CASE STUDIES ERROR:", error);
    return NextResponse.json(
      { success: false, error: "Failed to fetch case studies." },
      { status: 500 }
    );
  }
}

export async function POST(req: Request) {
  try {
    const session = await auth();
    if (!session) {
      return new NextResponse("Unauthorized", { status: 401 });
    }

    const body = await req.json();
    const {
      slug,
      client,
      title,
      category,
      service,
      timeline,
      industry,
      heroImage,
      challenge,
      solution,
      metrics,
      results,
      featured,
    } = body;

    // Validate required fields
    if (
      !slug ||
      !client ||
      !title ||
      !category ||
      !service ||
      !timeline ||
      !industry ||
      !heroImage ||
      !challenge ||
      !solution ||
      !metrics ||
      !results
    ) {
      return NextResponse.json(
        { success: false, error: "Missing required fields." },
        { status: 400 }
      );
    }

    // Check if slug is unique
    const existing = await db.caseStudy.findUnique({
      where: { slug },
    });

    if (existing) {
      return NextResponse.json(
        { success: false, error: "A case study with this slug already exists." },
        { status: 400 }
      );
    }

    // If setting as featured, optionally unfeature other case studies
    if (featured) {
      await db.caseStudy.updateMany({
        where: { featured: true },
        data: { featured: false },
      });
    }

    const caseStudy = await db.caseStudy.create({
      data: {
        slug,
        client,
        title,
        category,
        service,
        timeline,
        industry,
        heroImage,
        challenge,
        solution,
        metrics,
        results,
        featured: !!featured,
      },
    });

    return NextResponse.json({ success: true, caseStudy });
  } catch (error: any) {
    console.error("POST CASE STUDY ERROR:", error);
    return NextResponse.json(
      { success: false, error: "Failed to create case study." },
      { status: 500 }
    );
  }
}

import { NextResponse } from "next/server";
import { db } from "@/lib/db";
import { auth } from "@/auth";

export async function DELETE(
  _req: Request,
  { params }: { params: { id: string } }
) {
  try {
    const session = await auth();
    if (!session) {
      return new NextResponse("Unauthorized", { status: 401 });
    }

    const { id } = params;
    const existing = await db.chatSession.findUnique({
      where: { id },
    });

    if (!existing) {
      return NextResponse.json(
        { success: false, error: "Chat session not found." },
        { status: 404 }
      );
    }

    // Delete chat session. Cascade delete is configured on the database level via Prisma schema
    await db.chatSession.delete({
      where: { id },
    });

    return NextResponse.json({
      success: true,
      message: "Chat session and cascading messages successfully deleted.",
    });
  } catch (error: any) {
    console.error("DELETE CHAT SESSION ERROR:", error);
    return NextResponse.json(
      { success: false, error: error?.message || "Failed to delete chat session." },
      { status: 500 }
    );
  }
}

import { NextRequest } from "next/server";
import { db } from "@/lib/db";

export const dynamic = "force-dynamic";

export async function POST(req: NextRequest) {
  try {
    const body = await req.json();
    const { sessionId, name, email, service, budget, message } = body;

    if (!name || !email) {
      return Response.json({ error: "Name and Email are required to register a lead." }, { status: 400 });
    }

    // 1. Create the lead in the Lead table
    const lead = await db.lead.create({
      data: {
        name,
        email,
        service: service || "General Inquiry",
        budget: budget || "Not Specified",
        message: message || "Lead generated via AI Chatbot conversation.",
        status: "New",
      },
    });

    // 2. Link to ChatSession if sessionId is provided
    if (sessionId) {
      const sessionExists = await db.chatSession.findUnique({
        where: { id: sessionId },
      });

      if (sessionExists) {
        await db.chatSession.update({
          where: { id: sessionId },
          data: {
            leadId: lead.id,
          },
        });
      }
    }

    return Response.json({
      success: true,
      leadId: lead.id,
      message: "Lead registered and linked successfully.",
    });
  } catch (err: any) {
    console.error("API /api/chat/lead error:", err);
    return Response.json({ error: err?.message || "Internal server error" }, { status: 500 });
  }
}

