function isValidImageSignature(buffer: Buffer): boolean {
  if (buffer.length < 4) return false;
  // JPEG: FF D8 FF
  if (buffer[0] === 0xFF && buffer[1] === 0xD8 && buffer[2] === 0xFF) return true;
  // PNG: 89 50 4E 47
  if (buffer[0] === 0x89 && buffer[1] === 0x50 && buffer[2] === 0x4E && buffer[3] === 0x47) return true;
  // GIF: 47 49 46 38 ('GIF8')
  if (buffer[0] === 0x47 && buffer[1] === 0x49 && buffer[2] === 0x46 && buffer[3] === 0x38) return true;
  // WEBP: RIFF....WEBP
  if (buffer.length >= 12 &&
      buffer[0] === 0x52 && buffer[1] === 0x49 && buffer[2] === 0x46 && buffer[3] === 0x46 && // RIFF
      buffer[8] === 0x57 && buffer[9] === 0x45 && buffer[10] === 0x42 && buffer[11] === 0x50) { // WEBP
    return true;
  }
  return false;
}

function isValidVideoSignature(buffer: Buffer): boolean {
  if (buffer.length < 8) return false;
  // MP4: usually has 'ftyp' at offset 4-7
  const isMp4 = buffer[4] === 0x66 && buffer[5] === 0x74 && buffer[6] === 0x79 && buffer[7] === 0x70; // ftyp
  // WebM: starts with 1A 45 DF A3
  const isWebm = buffer[0] === 0x1A && buffer[1] === 0x45 && buffer[2] === 0xDF && buffer[3] === 0xA3;
  // MOV: usually starts with ftypqt (offset 4) or moov (offset 4)
  const isMov = (buffer[4] === 0x6d && buffer[5] === 0x6f && buffer[6] === 0x6f && buffer[7] === 0x76) || // moov
                (buffer[4] === 0x66 && buffer[5] === 0x74 && buffer[6] === 0x79 && buffer[7] === 0x70 && buffer[8] === 0x71 && buffer[9] === 0x74); // ftypqt
  return isMp4 || isWebm || isMov;
}

export async function POST(req: Request) {
  try {
    const session = await auth();
    if (!session) {
      return new NextResponse("Unauthorized", { status: 401 });
    }

    const formData = await req.formData();
    const files = formData.getAll("files") as File[];

    if (!files || files.length === 0) {
      return NextResponse.json(
        { success: false, error: "No files uploaded." },
        { status: 400 }
      );
    }

    const uploadDir = path.join(process.cwd(), "public", "uploads");

    // Ensure uploads directory exists
    if (!fs.existsSync(uploadDir)) {
      fs.mkdirSync(uploadDir, { recursive: true });
    }

    const uploadedItems = [];

    for (const file of files) {
      if (!file || !(file instanceof File)) {
        continue;
      }

      // Check MIME type
      let mediaType = "image";
      const mime = file.type;
      if (mime.startsWith("image/")) {
        mediaType = "image";
        // Check size limit: 10MB
        if (file.size > 10 * 1024 * 1024) {
          return NextResponse.json(
            { success: false, error: `Image ${file.name} exceeds 10MB limit.` },
            { status: 400 }
          );
        }
      } else if (mime.startsWith("video/")) {
        mediaType = "video";
        // Check size limit: 100MB
        if (file.size > 100 * 1024 * 1024) {
          return NextResponse.json(
            { success: false, error: `Video ${file.name} exceeds 100MB limit.` },
            { status: 400 }
          );
        }
      } else {
        return NextResponse.json(
          { success: false, error: `Unsupported file type: ${mime}` },
          { status: 400 }
        );
      }

      // Create unique sanitized filename
      const uniquePrefix = Date.now() + "-" + Math.round(Math.random() * 1e9);
      // Strip special characters except alphanumeric, dot, dash, underscore
      const sanitizedOriginalName = file.name.replace(/[^a-zA-Z0-9.-]/g, "_");
      const filename = `${uniquePrefix}-${sanitizedOriginalName}`;
      const filePath = path.join(uploadDir, filename);

      // Write file contents to disk
      const buffer = Buffer.from(await file.arrayBuffer());

      // Validate file signatures (magic bytes) to prevent extension spoofing
      if (mediaType === "image") {
        if (!isValidImageSignature(buffer)) {
          return NextResponse.json(
            { success: false, error: `Invalid image signature detected for ${file.name}.` },
            { status: 400 }
          );
        }
      } else if (mediaType === "video") {
        if (!isValidVideoSignature(buffer)) {
          return NextResponse.json(
            { success: false, error: `Invalid video signature detected for ${file.name}.` },
            { status: 400 }
          );
        }
      }

      await fs.promises.writeFile(filePath, buffer);

      // Prettify original name for default title
      const dotIndex = file.name.lastIndexOf(".");
      const baseName = dotIndex !== -1 ? file.name.substring(0, dotIndex) : file.name;
      const defaultTitle = baseName
        .replace(/[-_]+/g, " ")
        .replace(/\b\w/g, (c) => c.toUpperCase());

      uploadedItems.push({
        url: `/uploads/${filename}`,
        type: mediaType,
        title: defaultTitle,
      });
    }

    return NextResponse.json({ success: true, uploadedItems });
  } catch (error: any) {
    console.error("UPLOAD API ERROR:", error);
    return NextResponse.json(
      { success: false, error: "Internal server error during upload." },
      { status: 500 }
    );
  }
}

