}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Loader2, ArrowLeft, Plus, X, Star, StarOff } from "lucide-react";
import Link from "next/link";

interface Metric {
  label: string;
  value: string;
  iconName: string;
}

interface CaseStudyData {
  id?: string;
  slug: string;
  client: string;
  title: string;
  category: string;
  service: string;
  timeline: string;
  industry: string;
  heroImage: string;
  challenge: string;
  solution: string;
  metrics: Metric[];
  results: string[];
  featured: boolean;
}

interface CaseStudyFormProps {
  initialData?: CaseStudyData;
  mode: "create" | "edit";
}

const categoryOptions = [
  "E-Commerce",
  "B2B SaaS",
  "Local Business",
  "Healthcare",
  "Finance",
  "Education",
  "Real Estate",
  "Technology",
];

const iconOptions = [
  "TrendingUp",
  "DollarSign",
  "Users",
  "ShoppingCart",
  "BarChart3",
  "Target",
  "Zap",
  "Globe",
  "Eye",
  "Heart",
  "Star",
  "ArrowUpRight",
  "Percent",
  "Clock",
  "Award",
];

const defaultFormData: CaseStudyData = {
  slug: "",
  client: "",
  title: "",
  category: "E-Commerce",
  service: "",
  timeline: "",
  industry: "",
  heroImage: "",
  challenge: "",
  solution: "",
  metrics: [{ label: "", value: "", iconName: "TrendingUp" }],
  results: [""],
  featured: false,
};

export default function CaseStudyForm({ initialData, mode }: CaseStudyFormProps) {
  const router = useRouter();
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [formData, setFormData] = useState<CaseStudyData>(initialData || defaultFormData);

  const updateField = (field: keyof CaseStudyData, value: any) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
  };

  // Auto-generate slug from title
  const generateSlug = (title: string) => {
    return title
      .toLowerCase()
      .replace(/[^a-z0-9\s-]/g, "")
      .replace(/\s+/g, "-")
      .replace(/-+/g, "-")
      .trim();
  };

  const handleTitleChange = (value: string) => {
    updateField("title", value);
    if (mode === "create") {
      updateField("slug", generateSlug(value));
    }
  };

  // Metrics management
  const addMetric = () => {
    setFormData((prev) => ({
      ...prev,
      metrics: [...prev.metrics, { label: "", value: "", iconName: "TrendingUp" }],
    }));
  };

  const removeMetric = (index: number) => {
    setFormData((prev) => ({
      ...prev,
      metrics: prev.metrics.filter((_, i) => i !== index),
    }));
  };

  const updateMetric = (index: number, field: keyof Metric, value: string) => {
    setFormData((prev) => {
      const updated = [...prev.metrics];
      updated[index] = { ...updated[index], [field]: value };
      return { ...prev, metrics: updated };
    });
  };

  // Results management
  const addResult = () => {
    setFormData((prev) => ({
      ...prev,
      results: [...prev.results, ""],
    }));
  };

  const removeResult = (index: number) => {
    setFormData((prev) => ({
      ...prev,
      results: prev.results.filter((_, i) => i !== index),
    }));
  };

  const updateResult = (index: number, value: string) => {
    setFormData((prev) => {
      const updated = [...prev.results];
      updated[index] = value;
      return { ...prev, results: updated };
    });
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError("");

    // Basic validation
    const requiredFields: (keyof CaseStudyData)[] = [
      "slug", "client", "title", "category", "service",
      "timeline", "industry", "heroImage", "challenge", "solution",
    ];
    for (const field of requiredFields) {
      if (!formData[field] || (typeof formData[field] === "string" && !(formData[field] as string).trim())) {
        setError(`Please fill in the "${field}" field.`);
