                ) : (
                  selectedSession.messages.map((msg) => {
                    const isUser = msg.role === "user";
                    return (
                      <div 
                        key={msg.id}
                        className={`flex ${isUser ? "justify-end" : "justify-start"} items-start space-x-2.5 max-w-[85%] ${
                          isUser ? "ml-auto" : "mr-auto"
                        }`}
                      >
                        {!isUser && (
                          <div className="w-8 h-8 rounded-full bg-yellow-400 text-black flex items-center justify-center flex-shrink-0 shadow-inner mt-1">
                            <Zap className="w-4 h-4 fill-current" />
                          </div>
                        )}
                        <div className="flex flex-col">
                          <div className={`px-4 py-3 rounded-2xl text-sm leading-relaxed ${
                            isUser 
                              ? "bg-yellow-400 text-black font-medium rounded-tr-sm shadow-sm" 
                              : "bg-white dark:bg-zinc-900 border border-slate-200 dark:border-zinc-800 text-slate-850 dark:text-zinc-150 rounded-tl-sm shadow-sm"
                          }`}>
                            {isUser ? (
                              <p className="whitespace-pre-wrap">{formatMessageText(msg.content)}</p>
                            ) : (
                              renderMessageContent(msg.content)
                            )}
                          </div>
                          <span className={`text-[9px] text-slate-400 mt-1 ${isUser ? "text-right" : "text-left"}`}>
                            {formatDate(msg.createdAt)}
                          </span>
                        </div>
                      </div>
                    );
                  })
                )}
              </div>
            </>
          ) : (
            <div className="flex-1 flex flex-col items-center justify-center text-slate-400">
              <MessageSquare className="w-12 h-12 text-slate-300 mb-3 animate-bounce" />
              <h3 className="font-bold text-sm">No Session Selected</h3>
              <p className="text-xs text-slate-450 mt-1">Select an active chat session from the list to review details.</p>
            </div>
          )}
        </div>

      </div>

    </div>
  );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/button";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Trash2, Loader2, Building2, Plus, Edit, Mail, Phone, Users, ShieldAlert } from "lucide-react";
import { format } from "date-fns";

interface Client {
  id: string;
  name: string;
  email: string;
  phone: string | null;
  company: string | null;
  service: string;
  status: string;
  createdAt: string;
  _count: {
    projects: number;
  };
}

interface ClientsClientProps {
  initialItems: Client[];
}

export default function ClientsClient({ initialItems }: ClientsClientProps) {
  const router = useRouter();
  const [deletingId, setDeletingId] = useState<string | null>(null);
  const [error, setError] = useState("");

  // Modal CRUD state
  const [showModal, setShowModal] = useState(false);
  const [editItem, setEditItem] = useState<Client | null>(null);
  const [saving, setSaving] = useState(false);
  const [form, setForm] = useState({
    name: "",
    email: "",
    company: "",
    phone: "",
    service: "Digital Marketing",
    status: "Active",
  });

  const openCreate = () => {
    setEditItem(null);
    setForm({
      name: "",
      email: "",
      company: "",
      phone: "",
      service: "Digital Marketing",
      status: "Active",
    });
    setShowModal(true);
  };

  const openEdit = (c: Client) => {
    setEditItem(c);
    setForm({
      name: c.name,
      email: c.email,
      company: c.company || "",
      phone: c.phone || "",
      service: c.service,
      status: c.status,
    });
    setShowModal(true);
  };

  const handleSave = async () => {
    if (!form.name.trim() || !form.email.trim() || !form.service.trim()) {
      setError("Please fill in all required fields.");
      return;
    }
    setSaving(true);
    setError("");
    try {
      const url = editItem ? `/api/clients/${editItem.id}` : "/api/clients";
      const method = editItem ? "PUT" : "POST";
      const res = await fetch(url, {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(form),
      });
      const json = await res.json();
      if (!res.ok || !json.success) throw new Error(json.error || "Failed to save client.");
      setShowModal(false);
      router.refresh();
    } catch (err: any) {
      setError(err.message);
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm("Are you sure? Deleting this client will permanently remove all their projects and invoices. This cannot be undone.")) return;
    setDeletingId(id);
    setError("");
    try {
      const res = await fetch(`/api/clients/${id}`, { method: "DELETE" });
      if (!res.ok) {
        const err = await res.json();
        throw new Error(err.error || "Failed to delete.");
      }
      router.refresh();
    } catch (err: any) {
      setError(err.message);
    } finally {
      setDeletingId(null);
    }
  };

  // Stats calculation
  const total = initialItems.length;
  const activeCount = initialItems.filter(c => c.status === "Active").length;
  const projectSum = initialItems.reduce((acc, c) => acc + c._count.projects, 0);

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center bg-white dark:bg-[#111111] p-6 rounded-xl border border-slate-200 dark:border-white/[0.06] shadow-sm gap-4 transition-colors duration-300">
        <div>
          <h1 className="text-2xl font-bold tracking-tight text-slate-900 dark:text-white mb-1">Clients CRM</h1>
          <p className="text-slate-500 dark:text-slate-400 text-sm">Manage your agency client list, profiles, and active projects.</p>
        </div>
        <Button
          onClick={openCreate}
          className="bg-yellow-400 text-black hover:bg-yellow-500 font-semibold shadow-[0_0_15px_rgba(250,204,21,0.3)] hover:shadow-[0_0_25px_rgba(250,204,21,0.5)] transition-all"
        >
          <Plus className="mr-2 h-4 w-4" /> Add Client
        </Button>
      </div>

      {error && (
        <div className="text-red-400 text-sm bg-red-400/10 p-3 rounded border border-red-400/20">
          {error}
        </div>
      )}

      {/* Stats row */}
      <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
        <div className="bg-white dark:bg-[#111111] border border-slate-200 dark:border-white/[0.06] p-5 rounded-xl flex items-center justify-between transition-colors duration-300 shadow-sm">
          <div>
            <p className="text-slate-500 dark:text-slate-400 text-xs font-semibold uppercase tracking-wider mb-1">Total Clients</p>
            <h3 className="text-2xl font-bold text-slate-900 dark:text-white">{total}</h3>
          </div>
          <div className="p-3 rounded-lg bg-yellow-400/10 text-yellow-600 dark:text-yellow-400">
            <Building2 className="w-5 h-5" />
          </div>
        </div>
        <div className="bg-white dark:bg-[#111111] border border-slate-200 dark:border-white/[0.06] p-5 rounded-xl flex items-center justify-between transition-colors duration-300 shadow-sm">
          <div>
            <p className="text-slate-500 dark:text-slate-400 text-xs font-semibold uppercase tracking-wider mb-1">Active Accounts</p>
            <h3 className="text-2xl font-bold text-slate-900 dark:text-white">{activeCount}</h3>
          </div>
          <div className="p-3 rounded-lg bg-emerald-500/10 text-emerald-600 dark:text-emerald-400">
            <Users className="w-5 h-5" />
          </div>
        </div>
        <div className="bg-white dark:bg-[#111111] border border-slate-200 dark:border-white/[0.06] p-5 rounded-xl flex items-center justify-between transition-colors duration-300 shadow-sm">
          <div>
            <p className="text-slate-500 dark:text-slate-400 text-xs font-semibold uppercase tracking-wider mb-1">Active Projects</p>
            <h3 className="text-2xl font-bold text-slate-900 dark:text-white">{projectSum}</h3>
          </div>
          <div className="p-3 rounded-lg bg-blue-500/10 text-blue-600 dark:text-blue-400">
            <ShieldAlert className="w-5 h-5" />
          </div>
        </div>
      </div>

      {/* Table */}
      <div className="bg-white dark:bg-[#111111] rounded-xl border border-slate-200 dark:border-white/[0.06] overflow-hidden shadow-sm transition-colors duration-300">
        {initialItems.length === 0 ? (
          <div className="p-12 text-center">
            <Building2 className="w-12 h-12 mx-auto mb-4 text-slate-400 dark:text-slate-700" />
            <h3 className="text-lg font-semibold text-slate-800 dark:text-slate-300">No clients yet</h3>
            <p className="text-slate-500 dark:text-slate-400 text-sm mt-1">Click &quot;Add Client&quot; to register your first agency account.</p>
          </div>
        ) : (
          <Table>
            <TableHeader>
              <TableRow className="border-slate-200 dark:border-zinc-800 hover:bg-transparent">
                <TableHead className="text-slate-500 dark:text-slate-400">Name</TableHead>
                <TableHead className="text-slate-500 dark:text-slate-400">Company</TableHead>
                <TableHead className="text-slate-500 dark:text-slate-400">Primary Service</TableHead>
                <TableHead className="text-slate-500 dark:text-slate-400 text-center w-[100px]">Projects</TableHead>
                <TableHead className="text-slate-500 dark:text-slate-400">Status</TableHead>
                <TableHead className="text-slate-500 dark:text-slate-400 text-right">Actions</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {initialItems.map((c) => (
                <TableRow key={c.id} className="border-slate-200 dark:border-zinc-800 hover:bg-slate-50 dark:hover:bg-zinc-900/50 transition-colors">
                  <TableCell>
                    <div className="flex flex-col">
                      <span className="font-semibold text-slate-900 dark:text-slate-100">{c.name}</span>
                      <span className="text-xs text-slate-500 flex items-center mt-1">
                        <Mail className="w-3 h-3 mr-1" /> {c.email}
                      </span>
                    </div>
                  </TableCell>
                  <TableCell className="text-slate-700 dark:text-slate-300 font-medium">{c.company || "—"}</TableCell>
                  <TableCell>
                    <span className="px-2.5 py-1 rounded-full text-xs font-semibold border bg-yellow-400/10 text-yellow-600 dark:text-yellow-400 border-yellow-400/20">
                      {c.service}
                    </span>
                  </TableCell>
                  <TableCell className="text-center font-bold text-slate-700 dark:text-slate-300">
                    {c._count.projects}
                  </TableCell>
                  <TableCell>
                    <span className={`px-2.5 py-1 rounded-full text-xs font-semibold border ${
                      c.status === "Active" 
                        ? "bg-emerald-500/10 text-emerald-600 dark:text-emerald-400 border-emerald-500/20" 
                        : "bg-slate-100 dark:bg-zinc-800 text-slate-500 dark:text-slate-400 border-slate-200 dark:border-zinc-800"
                    }`}>
                      {c.status}
                    </span>
                  </TableCell>
                  <TableCell className="text-right">
                    <div className="flex justify-end gap-2">
                      <Button
                        variant="ghost"
                        size="sm"
                        onClick={() => openEdit(c)}
                        className="h-8 bg-slate-50 dark:bg-zinc-900 text-slate-700 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-zinc-800 hover:text-slate-900 dark:hover:text-white border border-slate-200 dark:border-zinc-800 transition-colors"
                      >
                        <Edit className="h-4 w-4 mr-1.5" /> Edit
                      </Button>
                      <Button
                        variant="ghost"
                        size="icon"
                        disabled={deletingId === c.id}
                        onClick={() => handleDelete(c.id)}
                        className="h-8 w-8 text-slate-400 dark:text-slate-500 hover:text-red-500 dark:hover:text-red-400 hover:bg-red-500/10 transition-colors"
                      >
                        {deletingId === c.id ? (
                          <Loader2 className="w-4 h-4 animate-spin text-red-500 dark:text-red-400" />
                        ) : (
                          <Trash2 className="w-4 h-4" />
                        )}
                      </Button>
                    </div>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        )}
      </div>

      {/* Modal */}
      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
          <div className="bg-white dark:bg-[#111111] border border-slate-200 dark:border-white/[0.06] rounded-2xl w-full max-w-md p-6 space-y-5 shadow-2xl transition-colors duration-300">
            <h2 className="text-xl font-bold text-slate-900 dark:text-white">
              {editItem ? "Edit Client Profile" : "Add Client Profile"}
            </h2>

            <div className="space-y-4">
              <div className="space-y-1">
                <label className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Client Name *</label>
                <input
                  value={form.name}
                  onChange={(e) => setForm(p => ({ ...p, name: e.target.value }))}
                  placeholder="e.g. John Doe"
                  className="w-full bg-slate-50 dark:bg-black border border-slate-200 dark:border-zinc-800 rounded-lg px-3 py-2.5 text-slate-900 dark:text-slate-100 text-sm focus:outline-none focus:ring-2 focus:ring-yellow-400 transition-colors"
                />
              </div>

              <div className="space-y-1">
                <label className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Email Address *</label>
                <input
                  type="email"
                  value={form.email}
                  onChange={(e) => setForm(p => ({ ...p, email: e.target.value }))}
                  placeholder="e.g. john@techflow.com"
                  className="w-full bg-slate-50 dark:bg-black border border-slate-200 dark:border-zinc-800 rounded-lg px-3 py-2.5 text-slate-900 dark:text-slate-100 text-sm focus:outline-none focus:ring-2 focus:ring-yellow-400 transition-colors"
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Company</label>
                  <input
                    value={form.company}
                    onChange={(e) => setForm(p => ({ ...p, company: e.target.value }))}
                    placeholder="e.g. TechFlow LLC"
                    className="w-full bg-slate-50 dark:bg-black border border-slate-200 dark:border-zinc-800 rounded-lg px-3 py-2.5 text-slate-900 dark:text-slate-100 text-sm focus:outline-none focus:ring-2 focus:ring-yellow-400 transition-colors"
                  />
                </div>
                <div className="space-y-1">
                  <label className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Phone</label>
                  <input
                    value={form.phone}
                    onChange={(e) => setForm(p => ({ ...p, phone: e.target.value }))}
                    placeholder="e.g. +1 555-0199"
                    className="w-full bg-slate-50 dark:bg-black border border-slate-200 dark:border-zinc-800 rounded-lg px-3 py-2.5 text-slate-900 dark:text-slate-100 text-sm focus:outline-none focus:ring-2 focus:ring-yellow-400 transition-colors"
                  />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Service Category *</label>
                  <select
                    value={form.service}
                    onChange={(e) => setForm(p => ({ ...p, service: e.target.value }))}
                    className="w-full bg-slate-50 dark:bg-black border border-slate-200 dark:border-zinc-800 rounded-lg px-3 py-2.5 text-slate-900 dark:text-slate-100 text-sm focus:outline-none focus:ring-2 focus:ring-yellow-400 transition-colors"
                  >
                    <option value="Digital Marketing" className="bg-white dark:bg-black">Digital Marketing</option>
                    <option value="SEO Mastery" className="bg-white dark:bg-black">SEO Mastery</option>
                    <option value="Web Design" className="bg-white dark:bg-black">Web Design</option>
                    <option value="TikTok Shop Management" className="bg-white dark:bg-black">TikTok Shop Management</option>
                    <option value="Amazon FBA" className="bg-white dark:bg-black">Amazon FBA</option>
                    <option value="AI Solutions" className="bg-white dark:bg-black">AI Solutions</option>
                  </select>
                </div>
                <div className="space-y-1">
                  <label className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Account Status *</label>
                  <select
                    value={form.status}
                    onChange={(e) => setForm(p => ({ ...p, status: e.target.value }))}
                    className="w-full bg-slate-50 dark:bg-black border border-slate-200 dark:border-zinc-800 rounded-lg px-3 py-2.5 text-slate-900 dark:text-slate-100 text-sm focus:outline-none focus:ring-2 focus:ring-yellow-400 transition-colors"
                  >
                    <option value="Active" className="bg-white dark:bg-black">Active</option>
                    <option value="Inactive" className="bg-white dark:bg-black">Inactive</option>
                  </select>
                </div>
              </div>
            </div>

            <div className="flex justify-end gap-3 pt-2">
              <Button
                type="button"
                variant="ghost"
                onClick={() => setShowModal(false)}
                className="text-slate-500 hover:text-slate-900 dark:text-slate-400 dark:hover:text-white hover:bg-slate-100 dark:hover:bg-zinc-800"
              >
                Cancel
              </Button>
              <Button
                onClick={handleSave}
                disabled={saving}
                className="bg-yellow-400 text-black hover:bg-yellow-500 font-bold min-w-[120px] shadow-[0_0_15px_rgba(250,204,21,0.3)]"
              >
                {saving ? (
                  <span className="flex items-center"><Loader2 className="w-4 h-4 mr-2 animate-spin" /> Saving...</span>
                ) : editItem ? "Update" : "Publish"}
              </Button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/button";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Trash2, Loader2, Plus, Edit, Calendar, FileSpreadsheet, DollarSign, Clock, CheckCircle, Search, DownloadCloud } from "lucide-react";
import { format } from "date-fns";

interface Client {
  id: string;
  name: string;
  company: string | null;
}

interface Project {
  id: string;
  clientId: string;
  title: string;
}

interface Invoice {
  id: string;
  clientId: string;
  client: Client;
  projectId: string | null;
  project: Project | null;
  amount: number;
  currency: string;
  status: string;
  dueDate: string;
  paidAt: string | null;
  notes: string | null;
  createdAt: string;
}

interface InvoicesClientProps {
  initialItems: Invoice[];
  clients: Client[];
  projects: Project[];
}

export default function InvoicesClient({ initialItems, clients, projects }: InvoicesClientProps) {
  const router = useRouter();
  const [deletingId, setDeletingId] = useState<string | null>(null);
  const [error, setError] = useState("");
  const [searchTerm, setSearchTerm] = useState("");
  const [statusFilter, setStatusFilter] = useState("All");

  // Modal CRUD state
  const [showModal, setShowModal] = useState(false);
  const [editItem, setEditItem] = useState<Invoice | null>(null);
  const [saving, setSaving] = useState(false);

  const [form, setForm] = useState({
    clientId: "",
    projectId: "",
    amount: "",
    currency: "USD",
    status: "Unpaid",
    dueDate: new Date().toISOString().split("T")[0],
    paidAt: "",
    notes: "",
  });

  // Filtered projects for the modal based on selected client
  const [modalProjects, setModalProjects] = useState<Project[]>([]);

  useEffect(() => {
    if (form.clientId) {
      const filtered = projects.filter(p => p.clientId === form.clientId);
      setModalProjects(filtered);
      // If the selected project is no longer valid, reset it
      if (form.projectId && !filtered.some(p => p.id === form.projectId)) {
        setForm(prev => ({ ...prev, projectId: "" }));
      }
    } else {
      setModalProjects([]);
      setForm(prev => ({ ...prev, projectId: "" }));
    }
  }, [form.clientId, projects, form.projectId]);

  const openCreate = () => {
    setEditItem(null);
    setForm({
      clientId: clients[0]?.id || "",
      projectId: "",
      amount: "",
      currency: "USD",
      status: "Unpaid",
      dueDate: new Date(Date.now() + 14 * 24 * 60 * 60 * 1000).toISOString().split("T")[0], // 14 days default
      paidAt: "",
      notes: "",
    });
    setShowModal(true);
  };

  const openEdit = (i: Invoice) => {
    setEditItem(i);
    setForm({
      clientId: i.clientId,
      projectId: i.projectId || "",
      amount: i.amount.toString(),
      currency: i.currency,
      status: i.status,
      dueDate: i.dueDate ? i.dueDate.split("T")[0] : "",
      paidAt: i.paidAt ? i.paidAt.split("T")[0] : "",
      notes: i.notes || "",
    });
    setShowModal(true);
  };

  const handleSave = async () => {
    if (!form.clientId || !form.amount || !form.dueDate) {
      setError("Please fill in all required fields (Client, Amount, Due Date).");
      return;
    }
    if (parseFloat(form.amount) <= 0) {
      setError("Invoice amount must be greater than 0.");
      return;
    }
    setSaving(true);
    setError("");
    try {
      const url = editItem ? `/api/invoices/${editItem.id}` : "/api/invoices";
      const method = editItem ? "PUT" : "POST";
      const res = await fetch(url, {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          ...form,
          amount: parseFloat(form.amount),
          projectId: form.projectId || null,
          paidAt: form.status === "Paid" ? (form.paidAt ? new Date(form.paidAt).toISOString() : new Date().toISOString()) : null,
          dueDate: new Date(form.dueDate).toISOString(),
        }),
      });
      const json = await res.json();
      if (!res.ok || !json.success) throw new Error(json.error || "Failed to save invoice.");
      setShowModal(false);
      router.refresh();
    } catch (err: any) {
      setError(err.message);
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm("Are you sure? Deleting this invoice is permanent and cannot be undone.")) return;
    setDeletingId(id);
    setError("");
    try {
      const res = await fetch(`/api/invoices/${id}`, { method: "DELETE" });
      if (!res.ok) {
        const err = await res.json();
        throw new Error(err.error || "Failed to delete.");
      }
      router.refresh();
    } catch (err: any) {
      setError(err.message);
    } finally {
      setDeletingId(null);
    }
  };

  const getStatusStyle = (status: string) => {
    switch (status) {
      case "Paid": return "bg-emerald-500/10 text-emerald-400 border-emerald-500/20";
      case "Unpaid": return "bg-yellow-400/10 text-yellow-400 border-yellow-400/20";
      case "Overdue": return "bg-red-500/10 text-red-400 border-red-500/20";
      default: return "bg-slate-500/10 text-slate-400 border-slate-500/20";
    }
  };

  const formatMoney = (amount: number, currency = "USD") => {
    return new Intl.NumberFormat("en-US", { style: "currency", currency }).format(amount);
  };

  // Filter items
  const filteredItems = initialItems.filter((invoice) => {
    const matchesSearch = 
      (invoice.client?.name || "").toLowerCase().includes(searchTerm.toLowerCase()) ||
      (invoice.client?.company || "").toLowerCase().includes(searchTerm.toLowerCase()) ||
      (invoice.project?.title || "").toLowerCase().includes(searchTerm.toLowerCase()) ||
      `inv-${invoice.id.slice(-6)}`.toLowerCase().includes(searchTerm.toLowerCase());

    const matchesStatus = statusFilter === "All" || invoice.status === statusFilter;

    return matchesSearch && matchesStatus;
  });

  // Stats calculation
  const totalSum = initialItems.reduce((acc, item) => acc + item.amount, 0);
  const paidSum = initialItems.filter(i => i.status === "Paid").reduce((acc, item) => acc + item.amount, 0);
  const unpaidSum = initialItems.filter(i => i.status !== "Paid").reduce((acc, item) => acc + item.amount, 0);

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center bg-white dark:bg-[#111111] p-6 rounded-xl border border-slate-200 dark:border-white/[0.06] shadow-sm gap-4 transition-colors duration-300">
        <div>
          <h1 className="text-2xl font-bold tracking-tight text-slate-900 dark:text-white mb-1">Billing & Invoices</h1>
          <p className="text-slate-500 dark:text-slate-400 text-sm">Manage client payments, view overdue accounts, and generate new invoices.</p>
        </div>
        <Button
          onClick={openCreate}
          disabled={clients.length === 0}
          className="bg-yellow-400 text-black hover:bg-yellow-500 font-semibold shadow-[0_0_15px_rgba(250,204,21,0.3)] hover:shadow-[0_0_25px_rgba(250,204,21,0.5)] transition-all"
        >
          <Plus className="mr-2 h-4 w-4" /> Create Invoice
        </Button>
      </div>

      {clients.length === 0 && (
        <div className="text-yellow-400 text-sm bg-yellow-400/10 p-4 rounded-xl border border-yellow-400/20">
          ⚠️ <strong>Notice:</strong> You need to create at least one client in <a href="/admin/clients" className="underline font-bold">Clients CRM</a> before you can issue invoices.
        </div>
      )}

      {error && (
        <div className="text-red-400 text-sm bg-red-400/10 p-3 rounded border border-red-400/20">
          {error}
        </div>
      )}

      {/* Stats row */}
      <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
        <div className="bg-white dark:bg-[#111111] border border-slate-200 dark:border-white/[0.06] p-5 rounded-xl flex items-center justify-between shadow-sm transition-colors duration-300">
          <div>
            <p className="text-slate-500 dark:text-slate-400 text-xs font-semibold uppercase tracking-wider mb-1">Gross Invoiced</p>
            <h3 className="text-2xl font-bold text-slate-900 dark:text-white">{formatMoney(totalSum)}</h3>
          </div>
          <div className="p-3 rounded-lg bg-yellow-400/10 text-yellow-600 dark:text-yellow-400">
            <DollarSign className="w-5 h-5" />
          </div>
        </div>
        <div className="bg-white dark:bg-[#111111] border border-slate-200 dark:border-white/[0.06] p-5 rounded-xl flex items-center justify-between shadow-sm transition-colors duration-300">
          <div>
            <p className="text-slate-500 dark:text-slate-400 text-xs font-semibold uppercase tracking-wider mb-1">Collected Payments</p>
            <h3 className="text-2xl font-bold text-emerald-650 dark:text-emerald-450">{formatMoney(paidSum)}</h3>
          </div>
          <div className="p-3 rounded-lg bg-emerald-500/10 text-emerald-600 dark:text-emerald-400">
            <CheckCircle className="w-5 h-5" />
          </div>
        </div>
        <div className="bg-white dark:bg-[#111111] border border-slate-200 dark:border-white/[0.06] p-5 rounded-xl flex items-center justify-between shadow-sm transition-colors duration-300">
          <div>
            <p className="text-slate-500 dark:text-slate-400 text-xs font-semibold uppercase tracking-wider mb-1">Pending Receivables</p>
            <h3 className="text-2xl font-bold text-yellow-650 dark:text-yellow-400">{formatMoney(unpaidSum)}</h3>
          </div>
          <div className="p-3 rounded-lg bg-red-500/10 text-red-600 dark:text-red-400">
            <Clock className="w-5 h-5" />
          </div>
        </div>
      </div>

      {/* Search and Filters */}
      <div className="flex flex-col sm:flex-row gap-3 items-center justify-between bg-white dark:bg-[#111111] p-4 rounded-xl border border-slate-200 dark:border-white/[0.06] transition-colors duration-300 shadow-sm">
        <div className="relative w-full sm:w-72">
          <Search className="absolute left-3 top-2.5 h-4 w-4 text-slate-400 dark:text-slate-500" />
          <input
            type="text"
            placeholder="Search Invoice ID, client, project..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full bg-slate-100 dark:bg-black border border-slate-200 dark:border-zinc-800 rounded-lg pl-9 pr-3 py-2 text-slate-900 dark:text-slate-100 text-sm focus:outline-none focus:ring-1 focus:ring-yellow-400 transition-colors"
          />
        </div>
        <div className="flex gap-2 w-full sm:w-auto overflow-x-auto justify-end">
          {["All", "Paid", "Unpaid", "Overdue"].map((status) => (
            <button
              key={status}
              onClick={() => setStatusFilter(status)}
              className={`px-3 py-1.5 text-xs font-medium rounded-lg border transition-all whitespace-nowrap ${
                statusFilter === status
                  ? "bg-yellow-400 text-black border-yellow-400 font-bold"
                  : "bg-white dark:bg-black border-slate-200 dark:border-zinc-800 text-slate-600 dark:text-slate-400 hover:text-slate-900 dark:hover:text-white"
              }`}
            >
              {status}
            </button>
          ))}
        </div>
      </div>

      {/* Table */}
      <div className="bg-white dark:bg-[#111111] rounded-xl border border-slate-200 dark:border-white/[0.06] overflow-x-auto shadow-sm transition-colors duration-300">
        {filteredItems.length === 0 ? (
          <div className="p-12 text-center">
            <FileSpreadsheet className="w-12 h-12 mx-auto mb-4 text-slate-300 dark:text-slate-700" />
            <h3 className="text-lg font-semibold text-slate-700 dark:text-slate-300">No invoices found</h3>
            <p className="text-slate-500 dark:text-slate-500 text-sm mt-1">Refine your search or create a new invoice above.</p>
          </div>
        ) : (
          <Table>
            <TableHeader>
              <TableRow className="border-slate-200 dark:border-zinc-800 hover:bg-transparent">
                <TableHead className="text-slate-500 dark:text-slate-400">Invoice ID</TableHead>
                <TableHead className="text-slate-500 dark:text-slate-400">Client</TableHead>
                <TableHead className="text-slate-500 dark:text-slate-400">Project / Description</TableHead>
                <TableHead className="text-slate-500 dark:text-slate-400">Amount</TableHead>
                <TableHead className="text-slate-500 dark:text-slate-400">Due Date</TableHead>
                <TableHead className="text-slate-500 dark:text-slate-400">Status</TableHead>
                <TableHead className="text-slate-500 dark:text-slate-400 text-right">Actions</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {filteredItems.map((invoice) => (
                <TableRow key={invoice.id} className="border-slate-200 dark:border-zinc-800 hover:bg-slate-50 dark:hover:bg-zinc-900/40 transition-colors">
                  <TableCell className="font-medium text-slate-600 dark:text-slate-300 font-mono text-sm">
                    INV-{invoice.id.slice(-6).toUpperCase()}
                  </TableCell>
                  <TableCell className="font-medium text-slate-900 dark:text-slate-100">
                    {invoice.client?.company || invoice.client?.name || "—"}
                  </TableCell>
                  <TableCell className="text-slate-600 dark:text-slate-300">
                    {invoice.project?.title || invoice.notes || "General Billing"}
                  </TableCell>
                  <TableCell className="font-bold text-slate-900 dark:text-slate-100">
                    {formatMoney(invoice.amount, invoice.currency)}
                  </TableCell>
                  <TableCell className="text-slate-500 dark:text-slate-400 text-sm">
                    <span className="flex items-center">
                      <Calendar className="w-3.5 h-3.5 mr-1 text-slate-400 dark:text-slate-500" />
                      {format(new Date(invoice.dueDate), "MMM d, yyyy")}
                    </span>
                  </TableCell>
                  <TableCell>
                    <span className={`px-2.5 py-1 rounded-full text-xs font-semibold border ${getStatusStyle(invoice.status)}`}>
                      {invoice.status}
                    </span>
                  </TableCell>
                  <TableCell className="text-right">
                    <div className="flex justify-end gap-2">
                      <Button
                        variant="ghost"
                        size="icon"
                        onClick={() => {
                          alert(`Receipt Download Simulation:\nInvoice ID: INV-${invoice.id.toUpperCase()}\nClient: ${invoice.client?.name}\nAmount: ${formatMoney(invoice.amount, invoice.currency)}\nStatus: ${invoice.status}`);
                        }}
                        className="h-8 w-8 text-slate-500 dark:text-slate-400 bg-slate-100 dark:bg-zinc-900 hover:bg-slate-200 dark:hover:bg-zinc-800 hover:text-slate-900 dark:hover:text-white transition-colors"
                        title="Download Invoice Summary"
                      >
                        <DownloadCloud className="h-4 w-4" />
                      </Button>
                      <Button
                        variant="ghost"
                        size="sm"
                        onClick={() => openEdit(invoice)}
                        className="h-8 bg-slate-100 text-slate-700 hover:bg-slate-200 dark:bg-zinc-900 dark:text-slate-300 dark:hover:bg-zinc-800 dark:hover:text-white transition-colors"
                      >
                        <Edit className="h-4 w-4 mr-1.5" /> Edit
                      </Button>
                      <Button
                        variant="ghost"
                        size="icon"
                        disabled={deletingId === invoice.id}
                        onClick={() => handleDelete(invoice.id)}
                        className="h-8 w-8 text-slate-400 hover:text-red-650 dark:text-slate-500 dark:hover:text-red-400 hover:bg-red-50 dark:hover:bg-red-500/10 transition-colors"
                      >
                        {deletingId === invoice.id ? (
                          <Loader2 className="w-4 h-4 animate-spin text-red-650 dark:text-red-400" />
                        ) : (
                          <Trash2 className="w-4 h-4" />
                        )}
                      </Button>
                    </div>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        )}
      </div>

      {/* Modal */}
      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
          <div className="bg-white dark:bg-[#111111] border border-slate-200 dark:border-white/[0.06] rounded-2xl w-full max-w-md p-6 space-y-5 shadow-2xl transition-colors duration-300">
            <h2 className="text-xl font-bold text-slate-900 dark:text-white">
              {editItem ? "Edit Invoice Details" : "Create New Invoice"}
            </h2>

            <div className="space-y-4">
              <div className="space-y-1">
                <label className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Client *</label>
                <select
                  value={form.clientId}
                  onChange={(e) => setForm(p => ({ ...p, clientId: e.target.value }))}
                  className="w-full bg-slate-50 dark:bg-black border border-slate-200 dark:border-zinc-800 rounded-lg px-3 py-2.5 text-slate-900 dark:text-slate-100 text-sm focus:outline-none focus:ring-2 focus:ring-yellow-400"
                >
                  <option value="" disabled className="text-slate-500">Select client account</option>
                  {clients.map((c) => (
                    <option key={c.id} value={c.id} className="text-slate-900 dark:text-slate-100 bg-white dark:bg-[#111111]">
                      {c.company ? `${c.company} (${c.name})` : c.name}
                    </option>
                  ))}
                </select>
              </div>

              {form.clientId && (
                <div className="space-y-1">
                  <label className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Project Link (Optional)</label>
                  <select
                    value={form.projectId}
                    onChange={(e) => setForm(p => ({ ...p, projectId: e.target.value }))}
                    className="w-full bg-slate-50 dark:bg-black border border-slate-200 dark:border-zinc-800 rounded-lg px-3 py-2.5 text-slate-900 dark:text-slate-100 text-sm focus:outline-none focus:ring-2 focus:ring-yellow-400"
                  >
                    <option value="" className="text-slate-900 dark:text-slate-100 bg-white dark:bg-[#111111]">General / None (No associated project)</option>
                    {modalProjects.map((p) => (
                      <option key={p.id} value={p.id} className="text-slate-900 dark:text-slate-100 bg-white dark:bg-[#111111]">
                        {p.title}
                      </option>
                    ))}
                  </select>
                </div>
              )}

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Amount (USD) *</label>
                  <input
                    type="number"
                    step="0.01"
                    min="1"
                    value={form.amount}
                    onChange={(e) => setForm(p => ({ ...p, amount: e.target.value }))}
                    placeholder="0.00"
                    className="w-full bg-slate-50 dark:bg-black border border-slate-200 dark:border-zinc-800 rounded-lg px-3 py-2.5 text-slate-900 dark:text-slate-100 text-sm focus:outline-none focus:ring-2 focus:ring-yellow-400"
                  />
                </div>
                <div className="space-y-1">
                  <label className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Currency *</label>
                  <select
                    value={form.currency}
                    onChange={(e) => setForm(p => ({ ...p, currency: e.target.value }))}
                    className="w-full bg-slate-50 dark:bg-black border border-slate-200 dark:border-zinc-800 rounded-lg px-3 py-2.5 text-slate-900 dark:text-slate-100 text-sm focus:outline-none focus:ring-2 focus:ring-yellow-400"
                  >
                    <option value="USD" className="text-slate-900 dark:text-slate-100 bg-white dark:bg-[#111111]">USD ($)</option>
                    <option value="EUR" className="text-slate-900 dark:text-slate-100 bg-white dark:bg-[#111111]">EUR (€)</option>
                    <option value="GBP" className="text-slate-900 dark:text-slate-100 bg-white dark:bg-[#111111]">GBP (£)</option>
                    <option value="AUD" className="text-slate-900 dark:text-slate-100 bg-white dark:bg-[#111111]">AUD ($)</option>
                  </select>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Due Date *</label>
                  <input
                    type="date"
                    value={form.dueDate}
                    onChange={(e) => setForm(p => ({ ...p, dueDate: e.target.value }))}
                    className="w-full bg-slate-50 dark:bg-black border border-slate-200 dark:border-zinc-800 rounded-lg px-3 py-2.5 text-slate-900 dark:text-slate-100 text-sm focus:outline-none focus:ring-2 focus:ring-yellow-400"
                  />
                </div>
                <div className="space-y-1">
                  <label className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Status *</label>
                  <select
                    value={form.status}
                    onChange={(e) => setForm(p => ({ ...p, status: e.target.value }))}
                    className="w-full bg-slate-50 dark:bg-black border border-slate-200 dark:border-zinc-800 rounded-lg px-3 py-2.5 text-slate-900 dark:text-slate-100 text-sm focus:outline-none focus:ring-2 focus:ring-yellow-400"
                  >
                    <option value="Unpaid" className="text-slate-900 dark:text-slate-100 bg-white dark:bg-[#111111]">Unpaid</option>
                    <option value="Paid" className="text-slate-900 dark:text-slate-100 bg-white dark:bg-[#111111]">Paid</option>
                    <option value="Overdue" className="text-slate-900 dark:text-slate-100 bg-white dark:bg-[#111111]">Overdue</option>
                  </select>
                </div>
              </div>

              {form.status === "Paid" && (
                <div className="space-y-1">
                  <label className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Payment Received Date</label>
                  <input
                    type="date"
                    value={form.paidAt}
                    onChange={(e) => setForm(p => ({ ...p, paidAt: e.target.value }))}
                    className="w-full bg-slate-50 dark:bg-black border border-slate-200 dark:border-zinc-800 rounded-lg px-3 py-2.5 text-slate-900 dark:text-slate-100 text-sm focus:outline-none focus:ring-2 focus:ring-yellow-400"
                  />
                </div>
              )}

              <div className="space-y-1">
                <label className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Billing Description / Notes</label>
                <textarea
                  value={form.notes}
                  onChange={(e) => setForm(p => ({ ...p, notes: e.target.value }))}
                  placeholder="Billing terms, bank details, invoice scope notes..."
                  rows={3}
                  className="w-full bg-slate-50 dark:bg-black border border-slate-200 dark:border-zinc-800 rounded-lg px-3 py-2.5 text-slate-900 dark:text-slate-100 text-sm focus:outline-none focus:ring-2 focus:ring-yellow-400 resize-none"
                />
              </div>
            </div>

            <div className="flex justify-end gap-3 pt-2">
              <Button
                type="button"
                variant="ghost"
                onClick={() => setShowModal(false)}
                className="text-slate-500 dark:text-slate-400 hover:text-slate-900 dark:hover:text-white hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors"
              >
                Cancel
              </Button>
              <Button
                onClick={handleSave}
                disabled={saving}
                className="bg-yellow-400 text-black hover:bg-yellow-500 font-bold min-w-[120px] shadow-[0_0_15px_rgba(250,204,21,0.3)] transition-all"
              >
                {saving ? (
                  <span className="flex items-center"><Loader2 className="w-4 h-4 mr-2 animate-spin" /> Saving...</span>
                ) : editItem ? "Update" : "Publish"}
              </Button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/button";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Trash2, Loader2, Mail, MessageSquare, Phone, Eye, Check, X, UserCheck } from "lucide-react";
import { format } from "date-fns";

interface Lead {
  id: string;
  name: string;
  email: string;
  phone: string | null;
  service: string;
  message: string;
  budget: string | null;
  status: string;
  createdAt: string;
}

interface LeadsClientProps {
  initialItems: Lead[];
}

export default function LeadsClient({ initialItems }: LeadsClientProps) {
  const router = useRouter();
  const [deletingId, setDeletingId] = useState<string | null>(null);
  const [updatingId, setUpdatingId] = useState<string | null>(null);
  const [error, setError] = useState("");

  // Details Modal state
  const [selectedLead, setSelectedLead] = useState<Lead | null>(null);

  const handleStatusChange = async (id: string, newStatus: string) => {
    setUpdatingId(id);
    setError("");
    try {
      const res = await fetch(`/api/leads/${id}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ status: newStatus }),
      });
      const json = await res.json();
      if (!res.ok || !json.success) throw new Error(json.error || "Failed to update status.");

      // If we are currently viewing the updated lead, update the modal details too
      if (selectedLead && selectedLead.id === id) {
        setSelectedLead({ ...selectedLead, status: newStatus });
      }

      router.refresh();
    } catch (err: any) {
      setError(err.message);
    } finally {
      setUpdatingId(null);
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm("Are you sure you want to remove this lead inquiry? This cannot be undone.")) return;
    setDeletingId(id);
    setError("");
    try {
      const res = await fetch(`/api/leads/${id}`, { method: "DELETE" });
      if (!res.ok) {
        const err = await res.json();
        throw new Error(err.error || "Failed to delete.");
      }
      setSelectedLead(null);
      router.refresh();
    } catch (err: any) {
      setError(err.message);
    } finally {
      setDeletingId(null);
    }
  };

  const getStatusStyle = (status: string) => {
    switch (status) {
      case "New": return "bg-blue-500/10 text-blue-600 dark:text-blue-400 border-blue-500/20";
      case "Contacted": return "bg-yellow-400/10 text-yellow-600 dark:text-yellow-400 border-yellow-400/20";
      case "Converted": return "bg-emerald-500/10 text-emerald-600 dark:text-emerald-400 border-emerald-500/20";
      case "Rejected": return "bg-red-500/10 text-red-600 dark:text-red-400 border-red-500/20";
      default: return "bg-slate-100 dark:bg-slate-800 text-slate-500 dark:text-slate-450 border-slate-250 dark:border-slate-700";
    }
  };

  // Stats calculation
  const total = initialItems.length;
  const newCount = initialItems.filter(l => l.status === "New").length;
  const convertedCount = initialItems.filter(l => l.status === "Converted").length;

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex justify-between items-center bg-white dark:bg-[#111111] p-6 rounded-xl border border-slate-200 dark:border-white/[0.06] shadow-sm transition-colors duration-300">
        <div>
          <h1 className="text-2xl font-bold tracking-tight text-slate-900 dark:text-white mb-1">Incoming Leads</h1>
          <p className="text-slate-500 dark:text-slate-400 text-sm">Monitor and qualify agency inquiries from the website securely.</p>
        </div>
      </div>

      {error && (
        <div className="text-red-400 text-sm bg-red-400/10 p-3 rounded border border-red-400/20">
          {error}
        </div>
      )}

      {/* Stats row */}
      <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
        <div className="bg-white dark:bg-[#111111] border border-slate-200 dark:border-white/[0.06] p-5 rounded-xl flex items-center justify-between transition-colors duration-300 shadow-sm">
          <div>
            <p className="text-slate-500 dark:text-slate-400 text-xs font-semibold uppercase tracking-wider mb-1">Total Inquiries</p>
            <h3 className="text-2xl font-bold text-slate-900 dark:text-white">{total}</h3>
          </div>
          <div className="p-3 rounded-lg bg-yellow-400/10 text-yellow-650 dark:text-yellow-400">
            <MessageSquare className="w-5 h-5" />
          </div>
        </div>
        <div className="bg-white dark:bg-[#111111] border border-slate-200 dark:border-white/[0.06] p-5 rounded-xl flex items-center justify-between transition-colors duration-300 shadow-sm">
          <div>
            <p className="text-slate-500 dark:text-slate-400 text-xs font-semibold uppercase tracking-wider mb-1">Unprocessed Leads</p>
            <h3 className="text-2xl font-bold text-slate-900 dark:text-white">{newCount}</h3>
          </div>
          <div className="p-3 rounded-lg bg-blue-500/10 text-blue-600 dark:text-blue-400">
            <Eye className="w-5 h-5" />
          </div>
        </div>
        <div className="bg-white dark:bg-[#111111] border border-slate-200 dark:border-white/[0.06] p-5 rounded-xl flex items-center justify-between transition-colors duration-300 shadow-sm">
          <div>
            <p className="text-slate-500 dark:text-slate-400 text-xs font-semibold uppercase tracking-wider mb-1">Converted Clients</p>
            <h3 className="text-2xl font-bold text-slate-900 dark:text-white">{convertedCount}</h3>
          </div>
          <div className="p-3 rounded-lg bg-emerald-500/10 text-emerald-600 dark:text-emerald-400">
            <UserCheck className="w-5 h-5" />
          </div>
        </div>
      </div>

      {/* Table */}
      <div className="bg-white dark:bg-[#111111] rounded-xl border border-slate-200 dark:border-white/[0.06] overflow-hidden shadow-sm transition-colors duration-300">
        {initialItems.length === 0 ? (
          <div className="p-12 text-center">
            <MessageSquare className="w-12 h-12 mx-auto mb-4 text-slate-400 dark:text-slate-700" />
            <h3 className="text-lg font-semibold text-slate-800 dark:text-slate-300">No leads found</h3>
            <p className="text-slate-500 dark:text-slate-450 text-sm mt-1">Incoming inquiries from your site forms will appear here.</p>
          </div>
        ) : (
          <Table>
            <TableHeader>
              <TableRow className="border-slate-200 dark:border-zinc-800 hover:bg-transparent">
                <TableHead className="text-slate-500 dark:text-slate-400 w-[140px]">Date</TableHead>
                <TableHead className="text-slate-500 dark:text-slate-400">Prospect</TableHead>
                <TableHead className="text-slate-500 dark:text-slate-400">Service Inquiry</TableHead>
                <TableHead className="text-slate-500 dark:text-slate-400">Budget</TableHead>
                <TableHead className="text-slate-500 dark:text-slate-400">Status</TableHead>
                <TableHead className="text-slate-500 dark:text-slate-400 text-right">Actions</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {initialItems.map((lead) => (
                <TableRow key={lead.id} className="border-slate-200 dark:border-zinc-800 hover:bg-slate-50 dark:hover:bg-zinc-900/50 transition-colors">
                  <TableCell className="text-slate-500 dark:text-slate-400 text-sm">
                    {format(new Date(lead.createdAt), "MMM d, yyyy")}
                  </TableCell>
                  <TableCell>
                    <div className="flex flex-col">
                      <span className="font-semibold text-slate-900 dark:text-slate-100">{lead.name}</span>
                      <span className="text-xs text-slate-500 flex items-center mt-1">
                        <Mail className="w-3 h-3 mr-1" /> {lead.email}
                      </span>
                    </div>
                  </TableCell>
                  <TableCell className="text-slate-800 dark:text-slate-300 font-semibold">{lead.service}</TableCell>
                  <TableCell className="text-slate-600 dark:text-slate-400 font-mono text-sm">{lead.budget || "Not specified"}</TableCell>
                  <TableCell>
                    {updatingId === lead.id ? (
                      <span className="flex items-center text-xs text-slate-500">
                        <Loader2 className="w-3.5 h-3.5 mr-1 animate-spin" /> Updating...
                      </span>
                    ) : (
                      <span className={`px-2.5 py-1 rounded-full text-xs font-semibold border ${getStatusStyle(lead.status)}`}>
                        {lead.status}
                      </span>
                    )}
                  </TableCell>
                  <TableCell className="text-right">
                    <div className="flex justify-end gap-2">
                      <Button
                        variant="ghost"
                        size="sm"
                        onClick={() => setSelectedLead(lead)}
                        className="h-8 bg-slate-50 dark:bg-zinc-900 text-slate-700 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-zinc-800 hover:text-slate-900 dark:hover:text-white border border-slate-200 dark:border-zinc-800 transition-colors"
                      >
                        <Eye className="h-4 w-4 mr-1.5" /> View
                      </Button>
                      <Button
                        variant="ghost"
                        size="icon"
                        disabled={deletingId === lead.id}
                        onClick={() => handleDelete(lead.id)}
                        className="h-8 w-8 text-slate-400 dark:text-slate-500 hover:text-red-500 dark:hover:text-red-400 hover:bg-red-500/10 transition-colors"
                      >
                        {deletingId === lead.id ? (
                          <Loader2 className="w-4 h-4 animate-spin text-red-500 dark:text-red-450" />
                        ) : (
                          <Trash2 className="w-4 h-4" />
                        )}
                      </Button>
                    </div>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        )}
      </div>

      {/* Details View Modal */}
      {selectedLead && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
          <div className="bg-white dark:bg-[#111111] border border-slate-200 dark:border-white/[0.06] rounded-2xl w-full max-w-lg p-6 space-y-6 shadow-2xl transition-colors duration-300">
            <div className="flex justify-between items-start border-b border-slate-200 dark:border-zinc-800 pb-4">
              <div>
                <h2 className="text-xl font-bold text-slate-900 dark:text-white">{selectedLead.name}</h2>
                <p className="text-slate-500 dark:text-slate-400 text-xs mt-0.5">Inquiry received on {format(new Date(selectedLead.createdAt), "MMMM d, yyyy h:mm a")}</p>
              </div>
              <span className={`px-2.5 py-1 rounded-full text-xs font-semibold border ${getStatusStyle(selectedLead.status)}`}>
                {selectedLead.status}
              </span>
            </div>

            <div className="grid grid-cols-2 gap-4 text-sm bg-slate-50 dark:bg-black p-4 rounded-xl border border-slate-200 dark:border-zinc-800">
              <div className="space-y-1">
                <span className="text-slate-500 dark:text-slate-400 text-xs uppercase tracking-wider block">Email Address</span>
                <a href={`mailto:${selectedLead.email}`} className="text-yellow-600 dark:text-yellow-400 hover:underline flex items-center gap-1 font-semibold">
                  <Mail className="w-4 h-4 text-slate-400" /> {selectedLead.email}
                </a>
              </div>
              <div className="space-y-1">
                <span className="text-slate-500 dark:text-slate-400 text-xs uppercase tracking-wider block">Phone Number</span>
                <span className="text-slate-800 dark:text-slate-200 font-semibold flex items-center gap-1">
                  <Phone className="w-4 h-4 text-slate-400" /> {selectedLead.phone || "—"}
                </span>
              </div>
              <div className="space-y-1 mt-2">
                <span className="text-slate-500 dark:text-slate-400 text-xs uppercase tracking-wider block">Service Inquiry</span>
                <span className="text-slate-800 dark:text-slate-200 font-semibold">{selectedLead.service}</span>
              </div>
              <div className="space-y-1 mt-2">
                <span className="text-slate-500 dark:text-slate-400 text-xs uppercase tracking-wider block">Estimated Budget</span>
                <span className="text-yellow-600 dark:text-yellow-400 font-bold font-mono">{selectedLead.budget || "Not specified"}</span>
              </div>
            </div>

            <div className="space-y-2">
              <span className="text-slate-500 dark:text-slate-400 text-xs uppercase tracking-wider block font-semibold">Message Inquiry</span>
              <div className="bg-slate-50 dark:bg-black p-4 rounded-xl border border-slate-200 dark:border-zinc-800 text-slate-700 dark:text-slate-300 text-sm leading-relaxed whitespace-pre-wrap max-h-[160px] overflow-y-auto">
                {selectedLead.message}
              </div>
            </div>

            {/* Actions & Status Selection */}
            <div className="flex flex-col sm:flex-row justify-between items-center gap-4 pt-4 border-t border-slate-200 dark:border-zinc-800">
              <div className="flex gap-1 bg-slate-50 dark:bg-black p-1.5 rounded-lg border border-slate-200 dark:border-zinc-800 w-full sm:w-auto justify-center">
                {["New", "Contacted", "Converted", "Rejected"].map((status) => (
                  <button
                    key={status}
                    onClick={() => handleStatusChange(selectedLead.id, status)}
                    disabled={updatingId !== null}
                    className={`px-3 py-1.5 text-xs font-semibold rounded-md transition-all ${
                      selectedLead.status === status
                        ? "bg-yellow-400 text-black shadow-sm"
                        : "text-slate-500 hover:bg-slate-150 dark:hover:bg-zinc-800 hover:text-slate-900 dark:hover:text-white"
                    }`}
                  >
                    {status}
                  </button>
                ))}
              </div>

              <div className="flex gap-2 w-full sm:w-auto justify-end">
                <Button
                  type="button"
                  variant="ghost"
                  onClick={() => setSelectedLead(null)}
                  className="text-slate-500 hover:text-slate-900 dark:text-slate-400 dark:hover:text-white hover:bg-slate-100 dark:hover:bg-zinc-850 w-full sm:w-auto"
                >
                  Close
                </Button>
                <Button
                  onClick={() => handleDelete(selectedLead.id)}
                  disabled={deletingId !== null}
                  className="bg-red-500/10 border border-red-500/20 text-red-600 dark:text-red-400 hover:bg-red-500/20 font-bold w-full sm:w-auto"
                >
                  Delete Lead
                </Button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { Play, Image as ImageIcon, Trash2, ExternalLink, Loader2, ChevronLeft, ChevronRight } from "lucide-react";
import { Button } from "@/components/ui/button";
import AddPortfolioModal from "./AddPortfolioModal";

interface PortfolioItem {
  id: string;
  title: string;
  category: string;
  type: string;
  url: string;
  images: string[];
  createdAt: Date | string;
}

interface PortfolioClientProps {
  initialItems: PortfolioItem[];
}

export default function PortfolioClient({ initialItems }: PortfolioClientProps) {
  const router = useRouter();
  const [activeCategory, setActiveCategory] = useState("All");
  const [deletingId, setDeletingId] = useState<string | null>(null);
  const [error, setError] = useState("");

  // Track active slide index for each portfolio item ID
  const [activeIndices, setActiveIndices] = useState<Record<string, number>>({});

  const categories = [
    "All",
    "Amazon",
    "TikTok Shop",
    "Walmart",
    "eBay",
    "Social Media",
    "Web SEO",
    "Google Ads",
    "Web Development",
    "Graphics Designing",
    "Video Ads",
    "Account Reinstatement",
    "AI Solutions"
  ];

  const filteredItems = activeCategory === "All"
    ? initialItems
    : initialItems.filter(item => item.category === activeCategory);

  const handleDelete = async (id: string) => {
    if (!confirm("Are you sure you want to delete this portfolio item?")) return;

    setDeletingId(id);
    setError("");

    try {
      const res = await fetch(`/api/portfolio/${id}`, {
        method: "DELETE",
      });

      if (!res.ok) {
        const errData = await res.json();
        throw new Error(errData.error || "Failed to delete item");
      }

      router.refresh();
    } catch (err: any) {
      setError(err.message || "Failed to delete the portfolio item.");
    } finally {
      setDeletingId(null);
    }
  };

  const handlePrevSlide = (e: React.MouseEvent, itemId: string, maxSlides: number) => {
    e.preventDefault();
    e.stopPropagation();
    setActiveIndices((prev) => {
      const current = prev[itemId] || 0;
      const nextIdx = current === 0 ? maxSlides - 1 : current - 1;
      return { ...prev, [itemId]: nextIdx };
    });
  };

  const handleNextSlide = (e: React.MouseEvent, itemId: string, maxSlides: number) => {
    e.preventDefault();
    e.stopPropagation();
    setActiveIndices((prev) => {
      const current = prev[itemId] || 0;
      const nextIdx = current === maxSlides - 1 ? 0 : current + 1;
      return { ...prev, [itemId]: nextIdx };
    });
  };

  // Stats calculation
  const totalItems = initialItems.length;
  const imageCount = initialItems.filter(item => item.type === "image").length;
  const videoCount = initialItems.filter(item => item.type === "video").length;

  return (
    <div className="space-y-6">
      {/* Header & Metrics */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center bg-white dark:bg-[#111111] p-6 rounded-xl border border-slate-200 dark:border-white/[0.06] shadow-sm gap-4">
        <div>
          <h1 className="text-2xl font-bold tracking-tight text-slate-900 dark:text-white mb-1">Portfolio Manager</h1>
          <p className="text-slate-500 dark:text-slate-400 text-sm">Upload, categorize, and organize creative assets shown in the public showcase gallery.</p>
        </div>
        <AddPortfolioModal onSuccess={() => router.refresh()} />
      </div>

      {error && (
        <div className="text-red-400 text-sm bg-red-400/10 p-3 rounded border border-red-400/20 max-w-xl">
          {error}
        </div>
      )}

      {/* Stats Cards */}
      <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
        <div className="bg-white dark:bg-[#111111] border border-slate-200 dark:border-white/[0.06] p-5 rounded-xl flex items-center justify-between">
          <div>
            <p className="text-slate-500 dark:text-slate-400 text-xs font-semibold uppercase tracking-wider mb-1">Total Assets</p>
            <h3 className="text-2xl font-bold text-slate-900 dark:text-white">{totalItems}</h3>
          </div>
          <div className="p-3 rounded-lg bg-yellow-400/10 text-yellow-600 dark:text-yellow-400">
            <ExternalLink className="w-5 h-5" />
          </div>
        </div>

        <div className="bg-white dark:bg-[#111111] border border-slate-200 dark:border-white/[0.06] p-5 rounded-xl flex items-center justify-between">
          <div>
            <p className="text-slate-500 dark:text-slate-400 text-xs font-semibold uppercase tracking-wider mb-1">Images</p>
            <h3 className="text-2xl font-bold text-slate-900 dark:text-white">{imageCount}</h3>
          </div>
          <div className="p-3 rounded-lg bg-emerald-500/10 text-emerald-600 dark:text-emerald-400">
            <ImageIcon className="w-5 h-5" />
          </div>
        </div>

        <div className="bg-white dark:bg-[#111111] border border-slate-200 dark:border-white/[0.06] p-5 rounded-xl flex items-center justify-between">
          <div>
            <p className="text-slate-500 dark:text-slate-400 text-xs font-semibold uppercase tracking-wider mb-1">Videos</p>
            <h3 className="text-2xl font-bold text-slate-900 dark:text-white">{videoCount}</h3>
          </div>
          <div className="p-3 rounded-lg bg-blue-500/10 text-blue-600 dark:text-blue-400">
            <Play className="w-5 h-5" />
          </div>
        </div>
      </div>

      {/* Navigation & Grid */}
      <div className="space-y-4">
        <div className="flex overflow-x-auto flex-nowrap items-center gap-2 border-b border-slate-200 dark:border-white/[0.06] pb-4 scrollbar-none">
          {categories.map((category) => (
            <button
              key={category}
              onClick={() => setActiveCategory(category)}
              className={`px-4 py-2 rounded-lg text-sm font-medium transition-all whitespace-nowrap ${
                activeCategory === category
                  ? "bg-slate-100 dark:bg-zinc-900 text-yellow-600 dark:text-yellow-400 shadow-sm border border-slate-200 dark:border-zinc-800"
                  : "text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-zinc-900/40 hover:text-slate-900 dark:hover:text-slate-200 border border-transparent"
              }`}
            >
              {category}
            </button>
          ))}
        </div>

        {filteredItems.length === 0 ? (
          <div className="bg-white dark:bg-[#111111] border border-slate-200 dark:border-white/[0.06] rounded-xl p-12 text-center text-slate-500">
            <ImageIcon className="w-12 h-12 mx-auto mb-4 text-slate-300 dark:text-slate-700" />
            <h3 className="text-lg font-semibold text-slate-800 dark:text-slate-300">No creative items found</h3>
            <p className="text-slate-500 text-sm mt-1">Try changing your category filters or add a new creative asset.</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
            {filteredItems.map((item) => {
              const slides = item.images && item.images.length > 0 ? item.images : [item.url];
              const currentIndex = activeIndices[item.id] || 0;
              const currentImageUrl = slides[currentIndex];
              const isMultiImage = slides.length > 1;

              return (
                <div 
                  key={item.id} 
                  className="group relative bg-white dark:bg-[#111111] border border-slate-200 dark:border-white/[0.06] rounded-xl overflow-hidden shadow-sm hover:shadow-lg transition-all flex flex-col h-full"
                >
                  {/* Media Preview Container */}
                  <div className="relative aspect-video w-full bg-slate-100 dark:bg-black overflow-hidden shrink-0">
                    <img
                      src={currentImageUrl}
                      alt={item.title}
                      className="w-full h-full object-cover transform group-hover:scale-105 transition-transform duration-500"
                      onError={(e) => {
                        e.currentTarget.src = "https://images.unsplash.com/photo-1618005182384-a83a8bd57fbe?q=80&w=1964&auto=format&fit=crop";
                      }}
                    />

                    {/* Badge */}
                    <span className={`absolute top-3 left-3 px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wider border z-10 ${
                      item.type === "video" 
                        ? "bg-blue-500/10 text-blue-400 border-blue-500/20" 
                        : "bg-emerald-500/10 text-emerald-400 border-emerald-500/20"
                    }`}>
                      {item.type}
                    </span>

                    {/* Multi-image Badge */}
                    {isMultiImage && (
                      <span className="absolute top-3 right-3 px-2 py-0.5 rounded text-[9px] font-bold uppercase tracking-wider border bg-yellow-400/10 text-yellow-400 border-yellow-400/25 z-10">
                        {slides.length} Photos
                      </span>
                    )}

                    {/* Slider Navigation arrows for Admin Preview */}
                    {isMultiImage && (
                      <div className="absolute inset-x-0 top-1/2 -translate-y-1/2 flex justify-between px-2 opacity-0 group-hover:opacity-100 transition-opacity z-20">
                        <button
                          type="button"
                          onClick={(e) => handlePrevSlide(e, item.id, slides.length)}
                          className="w-6 h-6 bg-slate-950/80 hover:bg-slate-900 rounded-full flex items-center justify-center text-white border border-slate-800 transition-colors"
                        >
                          <ChevronLeft className="w-3.5 h-3.5" />
                        </button>
                        <button
                          type="button"
                          onClick={(e) => handleNextSlide(e, item.id, slides.length)}
                          className="w-6 h-6 bg-slate-950/80 hover:bg-slate-900 rounded-full flex items-center justify-center text-white border border-slate-800 transition-colors"
                        >
                          <ChevronRight className="w-3.5 h-3.5" />
                        </button>
                      </div>
                    )}

                    {/* Slide Dots Indicator */}
                    {isMultiImage && (
                      <div className="absolute bottom-2.5 inset-x-0 flex justify-center space-x-1 z-10">
                        {slides.map((_, i) => (
                          <div 
                            key={i} 
                            className={`h-1.5 rounded-full transition-all ${
                              i === currentIndex ? "w-3 bg-yellow-400" : "w-1.5 bg-white/40"
                            }`}
                          />
                        ))}
                      </div>
                    )}

                    {/* Type overlay icon (video play) */}
                    {item.type === "video" && (
                      <div className="absolute inset-0 flex items-center justify-center bg-black/35 z-0">
                        <div className="w-10 h-10 bg-slate-900/80 backdrop-blur-sm rounded-full flex items-center justify-center text-white border border-slate-700">
                          <Play className="w-4 h-4 ml-0.5" fill="currentColor" />
                        </div>
                      </div>
                    )}
                  </div>

                  {/* Info & Action area */}
                  <div className="p-4 flex flex-col justify-between flex-grow">
                    <div className="mb-4">
                      <span className="text-[10px] text-yellow-600 dark:text-yellow-400 font-semibold uppercase tracking-wider block mb-1">
                        {item.category}
                      </span>
                      <h4 className="text-slate-800 dark:text-slate-100 font-semibold text-sm line-clamp-2 leading-snug">
                        {item.title}
                      </h4>
                    </div>

                    <div className="flex items-center justify-between border-t border-slate-200 dark:border-white/[0.06] pt-3 mt-auto">
                      <a 
                        href={currentImageUrl} 
                        target="_blank" 
                        rel="noopener noreferrer" 
                        className="text-xs text-slate-500 dark:text-slate-400 hover:text-slate-900 dark:hover:text-white flex items-center transition-colors"
                      >
                        View Source <ExternalLink className="w-3 h-3 ml-1" />
                      </a>

                      <Button 
                        variant="ghost" 
                        size="icon" 
                        disabled={deletingId === item.id}
                        onClick={() => handleDelete(item.id)}
                        className="h-8 w-8 text-slate-500 hover:text-red-400 hover:bg-red-500/10 transition-colors"
                      >
                        {deletingId === item.id ? (
                          <Loader2 className="w-4 h-4 animate-spin text-red-400" />
                        ) : (
                          <Trash2 className="w-4 h-4" />
                        )}
                      </Button>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/button";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Trash2, Loader2, Plus, Edit, Calendar, FolderKanban, Briefcase, CheckCircle2, Search } from "lucide-react";
import { format } from "date-fns";

interface Client {
  id: string;
  name: string;
  company: string | null;
}

interface Project {
  id: string;
  clientId: string;
  client: Client;
  service: string;
  title: string;
  status: string;
  startDate: string;
  deadline: string | null;
  notes: string | null;
}

interface ProjectsClientProps {
  initialItems: Project[];
  clients: Client[];
}

export default function ProjectsClient({ initialItems, clients }: ProjectsClientProps) {
  const router = useRouter();
  const [deletingId, setDeletingId] = useState<string | null>(null);
  const [error, setError] = useState("");
  const [searchTerm, setSearchTerm] = useState("");
  const [statusFilter, setStatusFilter] = useState("All");

  // Modal CRUD state
  const [showModal, setShowModal] = useState(false);
  const [editItem, setEditItem] = useState<Project | null>(null);
  const [saving, setSaving] = useState(false);

  const [form, setForm] = useState({
    clientId: "",
    title: "",
    service: "Digital Marketing",
    status: "Discovery",
    startDate: new Date().toISOString().split("T")[0],
    deadline: "",
    notes: "",
  });

  const openCreate = () => {
    setEditItem(null);
    setForm({
      clientId: clients[0]?.id || "",
      title: "",
      service: "Digital Marketing",
      status: "Discovery",
      startDate: new Date().toISOString().split("T")[0],
      deadline: "",
      notes: "",
    });
    setShowModal(true);
  };

  const openEdit = (p: Project) => {
    setEditItem(p);
    setForm({
      clientId: p.clientId,
      title: p.title,
      service: p.service,
      status: p.status,
      startDate: p.startDate ? p.startDate.split("T")[0] : new Date().toISOString().split("T")[0],
      deadline: p.deadline ? p.deadline.split("T")[0] : "",
      notes: p.notes || "",
    });
    setShowModal(true);
  };

  const handleSave = async () => {
    if (!form.clientId || !form.title.trim() || !form.service.trim()) {
      setError("Please fill in all required fields (Client, Title, Service).");
      return;
    }
    setSaving(true);
    setError("");
    try {
      const url = editItem ? `/api/projects/${editItem.id}` : "/api/projects";
      const method = editItem ? "PUT" : "POST";
      const res = await fetch(url, {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          ...form,
          deadline: form.deadline ? new Date(form.deadline).toISOString() : null,
          startDate: new Date(form.startDate).toISOString(),
        }),
      });
      const json = await res.json();
      if (!res.ok || !json.success) throw new Error(json.error || "Failed to save project.");
      setShowModal(false);
      router.refresh();
    } catch (err: any) {
      setError(err.message);
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm("Are you sure? Deleting this project will permanently remove it and all related invoices from the database. This cannot be undone.")) return;
    setDeletingId(id);
    setError("");
    try {
      const res = await fetch(`/api/projects/${id}`, { method: "DELETE" });
      if (!res.ok) {
        const err = await res.json();
        throw new Error(err.error || "Failed to delete.");
      }
      router.refresh();
    } catch (err: any) {
      setError(err.message);
    } finally {
      setDeletingId(null);
    }
  };

  const getStatusStyle = (status: string) => {
    switch (status) {
      case "Discovery": return "bg-blue-500/10 text-blue-600 dark:text-blue-400 border-blue-500/20";
      case "In Progress": return "bg-yellow-400/10 text-yellow-650 dark:text-yellow-400 border-yellow-400/20";
      case "Review": return "bg-orange-500/10 text-orange-600 dark:text-orange-400 border-orange-500/20";
      case "Completed": return "bg-emerald-500/10 text-emerald-600 dark:text-emerald-400 border-emerald-500/20";
      default: return "bg-slate-100 dark:bg-slate-800 text-slate-500 dark:text-slate-450 border-slate-250 dark:border-slate-700";
    }
  };

  // Filter items
  const filteredItems = initialItems.filter((project) => {
    const matchesSearch = 
      project.title.toLowerCase().includes(searchTerm.toLowerCase()) ||
      project.service.toLowerCase().includes(searchTerm.toLowerCase()) ||
      (project.client?.name || "").toLowerCase().includes(searchTerm.toLowerCase()) ||
      (project.client?.company || "").toLowerCase().includes(searchTerm.toLowerCase());

    const matchesStatus = statusFilter === "All" || project.status === statusFilter;

    return matchesSearch && matchesStatus;
  });

  // Stats
  const total = initialItems.length;
  const activeCount = initialItems.filter(p => p.status === "In Progress" || p.status === "Review").length;
  const completedCount = initialItems.filter(p => p.status === "Completed").length;

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center bg-white dark:bg-[#111111] p-6 rounded-xl border border-slate-200 dark:border-white/[0.06] shadow-sm gap-4 transition-colors duration-300">
        <div>
          <h1 className="text-2xl font-bold tracking-tight text-slate-900 dark:text-white mb-1">Projects Hub</h1>
          <p className="text-slate-500 dark:text-slate-400 text-sm">Track milestones, status updates, and deadlines for all active client workloads.</p>
        </div>
        <Button
          onClick={openCreate}
          disabled={clients.length === 0}
          className="bg-yellow-400 text-black hover:bg-yellow-500 font-semibold shadow-[0_0_15px_rgba(250,204,21,0.3)] hover:shadow-[0_0_25px_rgba(250,204,21,0.5)] transition-all"
        >
          <Plus className="mr-2 h-4 w-4" /> New Project
        </Button>
      </div>

      {clients.length === 0 && (
        <div className="text-yellow-600 dark:text-yellow-400 text-sm bg-yellow-400/10 p-4 rounded-xl border border-yellow-450/20">
          ⚠️ <strong>Notice:</strong> You need to create at least one client in the <a href="/admin/clients" className="underline font-bold">Clients CRM</a> before you can create projects.
        </div>
      )}

      {error && (
        <div className="text-red-400 text-sm bg-red-400/10 p-3 rounded border border-red-400/20">
          {error}
        </div>
      )}

      {/* Stats row */}
      <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
        <div className="bg-white dark:bg-[#111111] border border-slate-200 dark:border-white/[0.06] p-5 rounded-xl flex items-center justify-between transition-colors duration-300 shadow-sm">
          <div>
            <p className="text-slate-500 dark:text-slate-400 text-xs font-semibold uppercase tracking-wider mb-1">Total Projects</p>
            <h3 className="text-2xl font-bold text-slate-900 dark:text-white">{total}</h3>
          </div>
          <div className="p-3 rounded-lg bg-yellow-400/10 text-yellow-600 dark:text-yellow-400">
            <FolderKanban className="w-5 h-5" />
          </div>
        </div>
        <div className="bg-white dark:bg-[#111111] border border-slate-200 dark:border-white/[0.06] p-5 rounded-xl flex items-center justify-between transition-colors duration-300 shadow-sm">
          <div>
            <p className="text-slate-500 dark:text-slate-400 text-xs font-semibold uppercase tracking-wider mb-1">Active Deliveries</p>
            <h3 className="text-2xl font-bold text-slate-900 dark:text-white">{activeCount}</h3>
          </div>
          <div className="p-3 rounded-lg bg-blue-500/10 text-blue-600 dark:text-blue-400">
            <Briefcase className="w-5 h-5" />
          </div>
        </div>
        <div className="bg-white dark:bg-[#111111] border border-slate-200 dark:border-white/[0.06] p-5 rounded-xl flex items-center justify-between transition-colors duration-300 shadow-sm">
          <div>
            <p className="text-slate-500 dark:text-slate-400 text-xs font-semibold uppercase tracking-wider mb-1">Completed Works</p>
            <h3 className="text-2xl font-bold text-slate-900 dark:text-white">{completedCount}</h3>
          </div>
          <div className="p-3 rounded-lg bg-emerald-500/10 text-emerald-600 dark:text-emerald-400">
            <CheckCircle2 className="w-5 h-5" />
          </div>
        </div>
      </div>

      {/* Search and Filters */}
      <div className="flex flex-col sm:flex-row gap-3 items-center justify-between bg-white dark:bg-[#111111] p-4 rounded-xl border border-slate-200 dark:border-white/[0.06] transition-colors">
        <div className="relative w-full sm:w-72">
          <Search className="absolute left-3 top-2.5 h-4 w-4 text-slate-400 dark:text-slate-500" />
          <input
            type="text"
            placeholder="Search projects, client, service..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full bg-slate-50 dark:bg-black border border-slate-200 dark:border-zinc-800 rounded-lg pl-9 pr-3 py-2 text-slate-900 dark:text-slate-100 text-sm focus:outline-none focus:ring-1 focus:ring-yellow-400 transition-colors"
          />
        </div>
        <div className="flex gap-2 w-full sm:w-auto overflow-x-auto justify-end">
          {["All", "Discovery", "In Progress", "Review", "Completed"].map((status) => (
            <button
              key={status}
              onClick={() => setStatusFilter(status)}
              className={`px-3 py-1.5 text-xs font-medium rounded-lg border transition-all whitespace-nowrap ${
                statusFilter === status
                  ? "bg-yellow-400 text-black border-yellow-400 font-bold"
                  : "bg-slate-50 dark:bg-black border-slate-200 dark:border-zinc-800 text-slate-500 dark:text-slate-400 hover:text-slate-900 dark:hover:text-white"
              }`}
            >
              {status}
            </button>
          ))}
        </div>
      </div>

      {/* Table */}
      <div className="bg-white dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800 overflow-hidden shadow-sm transition-colors duration-300">
        {filteredItems.length === 0 ? (
          <div className="p-12 text-center">
            <FolderKanban className="w-12 h-12 mx-auto mb-4 text-slate-400 dark:text-slate-700" />
            <h3 className="text-lg font-semibold text-slate-850 dark:text-slate-300">No projects found</h3>
            <p className="text-slate-500 dark:text-slate-450 text-sm mt-1">Refine your search or create a new project above.</p>
          </div>
        ) : (
          <Table>
            <TableHeader>
              <TableRow className="border-slate-200 dark:border-slate-800 hover:bg-transparent">
                <TableHead className="text-slate-500 dark:text-slate-400">Project Info</TableHead>
                <TableHead className="text-slate-500 dark:text-slate-400">Client</TableHead>
                <TableHead className="text-slate-500 dark:text-slate-400">Service Category</TableHead>
                <TableHead className="text-slate-500 dark:text-slate-400">Status</TableHead>
                <TableHead className="text-slate-500 dark:text-slate-400">Deadline</TableHead>
                <TableHead className="text-slate-500 dark:text-slate-400 text-right">Actions</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {filteredItems.map((project) => (
                <TableRow key={project.id} className="border-slate-200 dark:border-slate-800 hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors">
                  <TableCell className="font-medium text-slate-900 dark:text-slate-100">
                    <div className="flex flex-col">
                      <span className="font-semibold">{project.title}</span>
                      <span className="text-xs text-slate-500 font-mono mt-0.5">#{project.id.slice(-6).toUpperCase()}</span>
                    </div>
                  </TableCell>
                  <TableCell className="text-slate-700 dark:text-slate-300 font-medium">
                    {project.client?.company || project.client?.name || "—"}
                  </TableCell>
                  <TableCell className="text-slate-700 dark:text-slate-300">
                    <span className="px-2 py-1 rounded-md text-xs bg-slate-50 dark:bg-slate-950 border border-slate-200 dark:border-slate-800 text-slate-600 dark:text-slate-300">
                      {project.service}
                    </span>
                  </TableCell>
                  <TableCell>
                    <span className={`px-2.5 py-1 rounded-full text-xs font-semibold border ${getStatusStyle(project.status)}`}>
                      {project.status}
                    </span>
                  </TableCell>
                  <TableCell className="text-slate-500 dark:text-slate-400 text-sm">
                    {project.deadline ? (
                      <span className="flex items-center">
                        <Calendar className="w-3 h-3 mr-1.5 text-yellow-500 dark:text-yellow-400" />
                        {format(new Date(project.deadline), "MMM d, yyyy")}
                      </span>
                    ) : (
                      <span className="text-slate-400 dark:text-slate-600">—</span>
                    )}
                  </TableCell>
                  <TableCell className="text-right">
                    <div className="flex justify-end gap-2">
                      <Button
                        variant="ghost"
                        size="sm"
                        onClick={() => openEdit(project)}
                        className="h-8 bg-slate-50 dark:bg-slate-800 text-slate-700 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-700 hover:text-slate-900 dark:hover:text-white border border-slate-200 dark:border-slate-700 transition-colors"
                      >
                        <Edit className="h-4 w-4 mr-1.5" /> Edit
                      </Button>
                      <Button
                        variant="ghost"
                        size="icon"
                        disabled={deletingId === project.id}
                        onClick={() => handleDelete(project.id)}
                        className="h-8 w-8 text-slate-450 dark:text-slate-500 hover:text-red-550 dark:hover:text-red-400 hover:bg-red-500/10 transition-colors"
                      >
                        {deletingId === project.id ? (
                          <Loader2 className="w-4 h-4 animate-spin text-red-500 dark:text-red-400" />
                        ) : (
                          <Trash2 className="w-4 h-4" />
                        )}
                      </Button>
                    </div>
                  </TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        )}
      </div>

      {/* Modal */}
      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
          <div className="bg-white dark:bg-[#111111] border border-slate-200 dark:border-white/[0.06] rounded-2xl w-full max-w-md p-6 space-y-5 shadow-2xl transition-colors duration-300">
            <h2 className="text-xl font-bold text-slate-900 dark:text-white">
              {editItem ? "Edit Project Details" : "Create New Project"}
            </h2>

            <div className="space-y-4">
              <div className="space-y-1">
                <label className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Client *</label>
                <select
                  value={form.clientId}
                  onChange={(e) => setForm(p => ({ ...p, clientId: e.target.value }))}
                  className="w-full bg-slate-50 dark:bg-black border border-slate-200 dark:border-zinc-800 rounded-lg px-3 py-2.5 text-slate-900 dark:text-slate-100 text-sm focus:outline-none focus:ring-2 focus:ring-yellow-400 transition-colors"
                >
                  <option value="" disabled>Select associated client</option>
                  {clients.map((c) => (
                    <option key={c.id} value={c.id} className="text-slate-900 dark:text-slate-100 bg-white dark:bg-black">
                      {c.company ? `${c.company} (${c.name})` : c.name}
                    </option>
                  ))}
                </select>
              </div>

              <div className="space-y-1">
                <label className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Project Title *</label>
                <input
                  value={form.title}
                  onChange={(e) => setForm(p => ({ ...p, title: e.target.value }))}
                  placeholder="e.g. TikTok UGC Ads Q3"
                  className="w-full bg-slate-50 dark:bg-black border border-slate-200 dark:border-zinc-800 rounded-lg px-3 py-2.5 text-slate-900 dark:text-slate-100 text-sm focus:outline-none focus:ring-2 focus:ring-yellow-400 transition-colors"
                />
              </div>

              <div className="space-y-1">
                <label className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Service Category *</label>
                <select
                  value={form.service}
                  onChange={(e) => setForm(p => ({ ...p, service: e.target.value }))}
                  className="w-full bg-slate-50 dark:bg-black border border-slate-200 dark:border-zinc-800 rounded-lg px-3 py-2.5 text-slate-900 dark:text-slate-100 text-sm focus:outline-none focus:ring-2 focus:ring-yellow-400 transition-colors"
                >
                  <option value="Digital Marketing" className="bg-white dark:bg-black">Digital Marketing</option>
                  <option value="SEO Mastery" className="bg-white dark:bg-black">SEO Mastery</option>
                  <option value="Web Design" className="bg-white dark:bg-black">Web Design</option>
                  <option value="TikTok Shop Management" className="bg-white dark:bg-black">TikTok Shop Management</option>
                  <option value="Amazon FBA" className="bg-white dark:bg-black">Amazon FBA</option>
                  <option value="AI Solutions" className="bg-white dark:bg-black">AI Solutions</option>
                </select>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Start Date *</label>
                  <input
                    type="date"
                    value={form.startDate}
                    onChange={(e) => setForm(p => ({ ...p, startDate: e.target.value }))}
                    className="w-full bg-slate-50 dark:bg-black border border-slate-200 dark:border-zinc-800 rounded-lg px-3 py-2.5 text-slate-900 dark:text-slate-100 text-sm focus:outline-none focus:ring-2 focus:ring-yellow-400 transition-colors"
                  />
                </div>
                <div className="space-y-1">
                  <label className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Deadline</label>
                  <input
                    type="date"
                    value={form.deadline}
                    onChange={(e) => setForm(p => ({ ...p, deadline: e.target.value }))}
                    className="w-full bg-slate-50 dark:bg-black border border-slate-200 dark:border-zinc-800 rounded-lg px-3 py-2.5 text-slate-900 dark:text-slate-100 text-sm focus:outline-none focus:ring-2 focus:ring-yellow-400 transition-colors"
                  />
                </div>
              </div>

              <div className="space-y-1">
                <label className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Project Status *</label>
                <select
                  value={form.status}
                  onChange={(e) => setForm(p => ({ ...p, status: e.target.value }))}
                  className="w-full bg-slate-50 dark:bg-black border border-slate-200 dark:border-zinc-800 rounded-lg px-3 py-2.5 text-slate-900 dark:text-slate-100 text-sm focus:outline-none focus:ring-2 focus:ring-yellow-400 transition-colors"
                >
                  <option value="Discovery" className="bg-white dark:bg-black">Discovery</option>
                  <option value="In Progress" className="bg-white dark:bg-black">In Progress</option>
                  <option value="Review" className="bg-white dark:bg-black">Review</option>
                  <option value="Completed" className="bg-white dark:bg-black">Completed</option>
                </select>
              </div>

              <div className="space-y-1">
                <label className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Notes</label>
                <textarea
                  value={form.notes}
                  onChange={(e) => setForm(p => ({ ...p, notes: e.target.value }))}
                  placeholder="Notes, briefs, scope details..."
                  rows={3}
                  className="w-full bg-slate-50 dark:bg-black border border-slate-200 dark:border-zinc-800 rounded-lg px-3 py-2.5 text-slate-900 dark:text-slate-100 text-sm focus:outline-none focus:ring-2 focus:ring-yellow-400 resize-none transition-colors"
                />
              </div>
            </div>

            <div className="flex justify-end gap-3 pt-2">
              <Button
                type="button"
                variant="ghost"
                onClick={() => setShowModal(false)}
                className="text-slate-500 hover:text-slate-900 dark:text-slate-400 dark:hover:text-white hover:bg-slate-100 dark:hover:bg-zinc-800"
              >
                Cancel
              </Button>
              <Button
                onClick={handleSave}
                disabled={saving}
                className="bg-yellow-400 text-black hover:bg-yellow-500 font-bold min-w-[120px] shadow-[0_0_15px_rgba(250,204,21,0.3)]"
              >
                {saving ? (
                  <span className="flex items-center"><Loader2 className="w-4 h-4 mr-2 animate-spin" /> Saving...</span>
                ) : editItem ? "Update" : "Publish"}
              </Button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/button";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Trash2, Loader2, Plus, Settings, User, ShieldAlert, Key, Globe, Sparkles, Check, CheckCircle2 } from "lucide-react";
import { format } from "date-fns";

interface UserProfile {
  id: string;
  name: string;
  email: string;
  role: string;
}

interface UserAdmin {
  id: string;
  name: string;
  email: string;
  role: string;
  createdAt: string;
}

interface AgencyFormState {
  agencyName: string;
  contactEmail: string;
  contactPhone: string;
  address: string;
  instagram: string;
  linkedin: string;
  timezone: string;
}

interface SettingsClientProps {
  currentUser: UserProfile;
  initialUsers: UserAdmin[];
}

export default function SettingsClient({ currentUser, initialUsers }: SettingsClientProps) {
  const router = useRouter();
  const [activeTab, setActiveTab] = useState<"profile" | "admins" | "agency">("profile");
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");
  const [saving, setSaving] = useState(false);
  const [deletingId, setDeletingId] = useState<string | null>(null);

  // Profile Form state
  const [profileForm, setProfileForm] = useState<{
    name: string;
    email: string;
    currentPassword: string;
    newPassword: string;
    confirmPassword: string;
  }>({
    name: currentUser.name || "",
    email: currentUser.email || "",
    currentPassword: "",
    newPassword: "",
    confirmPassword: "",
  });

  // Admin Registration Modal state
  const [showModal, setShowModal] = useState(false);
  const [adminSaving, setAdminSaving] = useState(false);
  const [adminForm, setAdminForm] = useState<{
    name: string;
    email: string;
    password: string;
  }>({
    name: "",
    email: "",
    password: "",
  });

  // Agency branding simulated local storage state
  const [agencyForm, setAgencyForm] = useState<AgencyFormState>(() => {
    const defaultState: AgencyFormState = {
      agencyName: "Alphadigify",
      contactEmail: "contact@alphadigify.com",
      contactPhone: "+1 (555) 019-2831",
      address: "100 Pine Street, San Francisco, CA 94111",
      instagram: "https://instagram.com/alphadigify",
      linkedin: "https://linkedin.com/company/alphadigify",
      timezone: "America/Los_Angeles",
    };

    if (typeof window !== "undefined") {
      const saved = localStorage.getItem("alphadigify_settings");
      if (saved) {
        try {
          const parsed = JSON.parse(saved);
          return { ...defaultState, ...parsed };
        } catch (_) {}
      }
    }
    return defaultState;
  });

  const handleProfileSave = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setSuccess("");

    if (!profileForm.name.trim() || !profileForm.email.trim()) {
      setError("Name and Email address are required fields.");
      return;
    }

    if (profileForm.newPassword) {
      if (!profileForm.currentPassword) {
        setError("You must enter your current password to authorize a password change.");
        return;
      }
      if (profileForm.newPassword !== profileForm.confirmPassword) {
        setError("New passwords do not match.");
        return;
      }
      if (profileForm.newPassword.length < 6) {
        setError("Your new password must be at least 6 characters.");
        return;
      }
    }

    setSaving(true);
    try {
      const res = await fetch("/api/admin/profile", {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          name: profileForm.name,
          email: profileForm.email,
          currentPassword: profileForm.currentPassword || undefined,
          newPassword: profileForm.newPassword || undefined,
        }),
      });

      const json = await res.json();
      if (!res.ok || !json.success) throw new Error(json.error || "Failed to update profile.");

      setSuccess("Profile settings updated successfully!");
      setProfileForm(prev => ({
        ...prev,
        currentPassword: "",
        newPassword: "",
        confirmPassword: "",
      }));
      router.refresh();
    } catch (err: any) {
      setError(err.message);
    } finally {
      setSaving(false);
    }
  };

  const handleAdminRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setSuccess("");

    if (!adminForm.name.trim() || !adminForm.email.trim() || !adminForm.password) {
      setError("Please fill in all fields to register an administrator.");
      return;
    }

    setAdminSaving(true);
    try {
      const res = await fetch("/api/admin/users", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(adminForm),
      });

      const json = await res.json();
      if (!res.ok || !json.success) throw new Error(json.error || "Registration failed.");

      setSuccess(`Admin account for ${adminForm.name} registered successfully!`);
      setShowModal(false);
      setAdminForm({ name: "", email: "", password: "" });
      router.refresh();
    } catch (err: any) {
      setError(err.message);
    } finally {
      setAdminSaving(false);
    }
  };

  const handleAdminDelete = async (id: string, name: string) => {
    if (!confirm(`Are you sure you want to revoke admin access for ${name}? they will immediately lose dashboard login privileges.`)) return;
    setError("");
    setSuccess("");
    setDeletingId(id);
    try {
      const res = await fetch(`/api/admin/users/${id}`, { method: "DELETE" });
      const json = await res.json();
      if (!res.ok || !json.success) throw new Error(json.error || "Failed to delete.");

      setSuccess(`Admin access for ${name} has been successfully revoked.`);
      router.refresh();
    } catch (err: any) {
      setError(err.message);
    } finally {
      setDeletingId(null);
    }
  };

  const handleAgencySave = (e: React.FormEvent) => {
    e.preventDefault();
    setError("");
    setSuccess("");
    setSaving(true);

    setTimeout(() => {
      if (typeof window !== "undefined") {
        localStorage.setItem("alphadigify_settings", JSON.stringify(agencyForm));
      }
      setSuccess("Agency contact details and branding updated successfully!");
      setSaving(false);
    }, 600);
  };

  return (
    <div className="space-y-6 max-w-5xl">
      {/* Header */}
      <div className="bg-white dark:bg-[#111111] p-6 rounded-xl border border-slate-200 dark:border-white/[0.06] shadow-sm flex flex-col md:flex-row justify-between items-start md:items-center gap-4 transition-colors duration-300">
        <div>
          <h1 className="text-2xl font-bold tracking-tight text-slate-900 dark:text-white mb-1 flex items-center gap-2">
            <Settings className="w-6 h-6 text-yellow-400" /> Settings Hub
          </h1>
          <p className="text-slate-500 dark:text-slate-400 text-sm">Configure personal profile details, manage administrator security access, and set dynamic configurations.</p>
        </div>
      </div>

      {error && (
        <div className="text-red-400 text-sm bg-red-400/10 p-3 rounded-xl border border-red-400/20 max-w-5xl">
          {error}
        </div>
      )}

      {success && (
        <div className="text-emerald-400 text-sm bg-emerald-500/10 p-3 rounded-xl border border-emerald-500/20 max-w-5xl flex items-center gap-2">
          <CheckCircle2 className="w-5 h-5 text-emerald-450" /> {success}
        </div>
      )}

      {/* Dynamic Settings Layout */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        {/* Navigation Tabs */}
        <div className="md:col-span-1 space-y-1">
          <button
            onClick={() => { setActiveTab("profile"); setError(""); setSuccess(""); }}
            className={`w-full text-left px-4 py-3 rounded-xl text-sm font-semibold flex items-center gap-3 transition-all ${
              activeTab === "profile"
                ? "bg-yellow-400 text-black shadow-lg"
                : "text-slate-500 dark:text-slate-400 hover:bg-slate-200/50 dark:hover:bg-zinc-900 hover:text-slate-900 dark:hover:text-white"
            }`}
          >
            <User className="w-4 h-4" /> My Account
          </button>
          <button
            onClick={() => { setActiveTab("admins"); setError(""); setSuccess(""); }}
            className={`w-full text-left px-4 py-3 rounded-xl text-sm font-semibold flex items-center gap-3 transition-all ${
              activeTab === "admins"
                ? "bg-yellow-400 text-black shadow-lg"
                : "text-slate-500 dark:text-slate-400 hover:bg-slate-200/50 dark:hover:bg-zinc-900 hover:text-slate-900 dark:hover:text-white"
            }`}
          >
            <ShieldAlert className="w-4 h-4" /> Team Admins
          </button>
          <button
            onClick={() => { setActiveTab("agency"); setError(""); setSuccess(""); }}
            className={`w-full text-left px-4 py-3 rounded-xl text-sm font-semibold flex items-center gap-3 transition-all ${
              activeTab === "agency"
                ? "bg-yellow-400 text-black shadow-lg"
                : "text-slate-500 dark:text-slate-400 hover:bg-slate-200/50 dark:hover:bg-zinc-900 hover:text-slate-900 dark:hover:text-white"
            }`}
          >
            <Globe className="w-4 h-4" /> Agency Profile
          </button>
        </div>

        {/* Content Panel */}
        <div className="md:col-span-3 bg-white dark:bg-[#111111] border border-slate-200 dark:border-white/[0.06] rounded-2xl p-6 shadow-sm transition-colors duration-300">
          {/* Tab 1: Personal Account Settings */}
          {activeTab === "profile" && (
            <form onSubmit={handleProfileSave} className="space-y-6">
              <div>
                <h3 className="text-lg font-bold text-slate-900 dark:text-white flex items-center gap-2">
                  <User className="w-5 h-5 text-yellow-400" /> Account Profile Details
                </h3>
                <p className="text-slate-500 dark:text-slate-400 text-xs mt-1">Manage your administrator account info, email verification, and master login passwords securely.</p>
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 pt-2">
                <div className="space-y-1">
                  <label className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Display Name *</label>
                  <input
                    value={profileForm.name}
                    onChange={(e) => setProfileForm(p => ({ ...p, name: e.target.value }))}
                    className="w-full bg-slate-50 dark:bg-black border border-slate-200 dark:border-zinc-800 rounded-lg px-3 py-2.5 text-slate-900 dark:text-slate-100 text-sm focus:outline-none focus:ring-2 focus:ring-yellow-400 transition-colors"
                  />
                </div>
                <div className="space-y-1">
                  <label className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Email Address *</label>
                  <input
                    type="email"
                    value={profileForm.email}
                    onChange={(e) => setProfileForm(p => ({ ...p, email: e.target.value }))}
                    className="w-full bg-slate-50 dark:bg-black border border-slate-200 dark:border-zinc-800 rounded-lg px-3 py-2.5 text-slate-900 dark:text-slate-100 text-sm focus:outline-none focus:ring-2 focus:ring-yellow-400 transition-colors"
                  />
                </div>
              </div>

              {/* Password Section */}
              <div className="border-t border-slate-150 dark:border-white/[0.06] pt-5 space-y-4">
                <div>
                  <h4 className="text-sm font-bold text-slate-800 dark:text-slate-200 flex items-center gap-2">
                    <Key className="w-4 h-4 text-yellow-400" /> Security Credentials Change
                  </h4>
                  <p className="text-slate-500 text-xs mt-0.5">Leave blank if you do not want to alter your security credentials password.</p>
                </div>

                <div className="space-y-3">
                  <div className="space-y-1">
                    <label className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Current Password</label>
                    <input
                      type="password"
                      value={profileForm.currentPassword}
                      onChange={(e) => setProfileForm(p => ({ ...p, currentPassword: e.target.value }))}
                      placeholder="Enter your current password"
                      className="w-full bg-slate-50 dark:bg-black border border-slate-200 dark:border-zinc-800 rounded-lg px-3 py-2.5 text-slate-900 dark:text-slate-100 text-sm focus:outline-none focus:ring-2 focus:ring-yellow-400 transition-colors"
                    />
                  </div>

                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                    <div className="space-y-1">
                      <label className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">New Password</label>
                      <input
                        type="password"
                        value={profileForm.newPassword}
                        onChange={(e) => setProfileForm(p => ({ ...p, newPassword: e.target.value }))}
                        placeholder="Minimum 6 characters"
                        className="w-full bg-slate-50 dark:bg-black border border-slate-200 dark:border-zinc-800 rounded-lg px-3 py-2.5 text-slate-900 dark:text-slate-100 text-sm focus:outline-none focus:ring-2 focus:ring-yellow-400 transition-colors"
                      />
                    </div>
                    <div className="space-y-1">
                      <label className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Confirm New Password</label>
                      <input
                        type="password"
                        value={profileForm.confirmPassword}
                        onChange={(e) => setProfileForm(p => ({ ...p, confirmPassword: e.target.value }))}
                        placeholder="Re-type new password"
                        className="w-full bg-slate-50 dark:bg-black border border-slate-200 dark:border-zinc-800 rounded-lg px-3 py-2.5 text-slate-900 dark:text-slate-100 text-sm focus:outline-none focus:ring-2 focus:ring-yellow-400 transition-colors"
                      />
                    </div>
                  </div>
                </div>
              </div>

              <div className="border-t border-slate-150 dark:border-white/[0.06] pt-4 flex justify-end">
                <Button
                  type="submit"
                  disabled={saving}
                  className="bg-yellow-400 text-black hover:bg-yellow-500 font-bold min-w-[150px] shadow-[0_0_15px_rgba(250,204,21,0.3)]"
                >
                  {saving ? (
                    <span className="flex items-center"><Loader2 className="w-4 h-4 mr-2 animate-spin" /> Saving...</span>
                  ) : "Save Settings"}
                </Button>
              </div>
            </form>
          )}

          {/* Tab 2: Administrators Directory */}
          {activeTab === "admins" && (
            <div className="space-y-6">
              <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <div>
                  <h3 className="text-lg font-bold text-slate-900 dark:text-white flex items-center gap-2">
                    <ShieldAlert className="w-5 h-5 text-yellow-400" /> Administrative Team Directory
                  </h3>
                  <p className="text-slate-500 dark:text-slate-400 text-xs mt-1">Authorized logins that hold access tokens to browse, update, and manage the administrative client database.</p>
                </div>
                <Button
                  onClick={() => setShowModal(true)}
                  className="bg-yellow-400 text-black hover:bg-yellow-500 font-bold text-xs"
                >
                  <Plus className="mr-1.5 h-3.5 w-3.5" /> Add Admin
                </Button>
              </div>

              <div className="bg-slate-50 dark:bg-black rounded-xl border border-slate-200 dark:border-white/[0.06] overflow-x-auto transition-colors">
                <Table>
                  <TableHeader>
                    <TableRow className="border-slate-200 dark:border-zinc-800 hover:bg-transparent">
                      <TableHead className="text-slate-500 dark:text-slate-400 text-xs">Name</TableHead>
                      <TableHead className="text-slate-500 dark:text-slate-400 text-xs">Email</TableHead>
