"use client";

import { motion } from "framer-motion";
import { ArrowRight } from "lucide-react";
import Link from "next/link";
import { useEffect, useState, useRef } from "react";

/* ───── Neural Network Animation ───── */
function NeuralNetworkBg() {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let particles: {x: number, y: number, vx: number, vy: number, radius: number}[] = [];
    let animationFrameId: number;

    const resize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
      init();
    };

    const init = () => {
      particles = [];
      const numParticles = Math.floor((canvas.width * canvas.height) / 12000); // Optimized density
      for (let i = 0; i < numParticles; i++) {
        particles.push({
          x: Math.random() * canvas.width,
          y: Math.random() * canvas.height,
          vx: (Math.random() - 0.5) * 1.5, 
          vy: (Math.random() - 0.5) * 1.5,
          radius: Math.random() * 4 + 2, // Huge nodes
        });
      }
    };

    const draw = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);

      const isDark = document.documentElement.classList.contains('dark');
      const colorRGB = '234, 179, 8'; // yellow-500

      for (let i = 0; i < particles.length; i++) {
        const p = particles[i];

        p.x += p.vx;
        p.y += p.vy;

        if (p.x < 0 || p.x > canvas.width) p.vx *= -1;
        if (p.y < 0 || p.y > canvas.height) p.vy *= -1;

        ctx.beginPath();
        ctx.arc(p.x, p.y, p.radius, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(${colorRGB}, ${isDark ? 1 : 0.9})`; // Maximum opacity nodes
        ctx.fill();

        for (let j = i + 1; j < particles.length; j++) {
          const p2 = particles[j];
          // Optimization: fast bounding box check before expensive Math.hypot
          if (Math.abs(p.x - p2.x) > 150 || Math.abs(p.y - p2.y) > 150) continue;

          const dist = Math.hypot(p.x - p2.x, p.y - p2.y);
          const maxDist = 150; // Optimized connection range
          if (dist < maxDist) {
            ctx.beginPath();
            ctx.moveTo(p.x, p.y);
            ctx.lineTo(p2.x, p2.y);
            const opacity = (1 - dist / maxDist) * (isDark ? 0.9 : 0.7); // Solid lines
            ctx.strokeStyle = `rgba(${colorRGB}, ${opacity})`;
            ctx.lineWidth = 2.0; // Thick lines
            ctx.stroke();
          }
        }
      }

      animationFrameId = requestAnimationFrame(draw);
    };

    window.addEventListener('resize', resize);
    resize();
    draw();

    return () => {
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(animationFrameId);
    };
  }, []);

  return <canvas ref={canvasRef} className="absolute inset-0 w-full h-full pointer-events-none opacity-100" />;
}

/* ───── 3D Tesseract Component ───── */
function Tesseract() {
  const outerFaces = [
    { rotateX: 0, rotateY: 0, translateZ: 96 },   // Front
    { rotateX: 0, rotateY: 180, translateZ: 96 }, // Back
    { rotateX: 0, rotateY: -90, translateZ: 96 }, // Left
    { rotateX: 0, rotateY: 90, translateZ: 96 },  // Right
    { rotateX: 90, rotateY: 0, translateZ: 96 },  // Top
    { rotateX: -90, rotateY: 0, translateZ: 96 }, // Bottom
  ];

  const innerFaces = [
    { rotateX: 0, rotateY: 0, translateZ: 48 },
    { rotateX: 0, rotateY: 180, translateZ: 48 },
    { rotateX: 0, rotateY: -90, translateZ: 48 },
    { rotateX: 0, rotateY: 90, translateZ: 48 },
    { rotateX: 90, rotateY: 0, translateZ: 48 },
    { rotateX: -90, rotateY: 0, translateZ: 48 },
