        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="text-center mb-16 lg:mb-24">
            <h2 className="text-3xl md:text-5xl font-black mb-6">Our Capabilities</h2>
            <p className="text-lg text-slate-600 dark:text-slate-400 max-w-2xl mx-auto">
              From pixel-perfect web interfaces to high-converting product packaging, we operate across all digital and physical touchpoints.
            </p>
          </div>

          <div className="grid md:grid-cols-2 lg:grid-cols-4 gap-6">
            {SERVICES.map((srv, i) => (
              <motion.div 
                key={i}
                initial={{ opacity: 0, y: 30 }}
                whileInView={{ opacity: 1, y: 0 }}
                viewport={{ once: true, margin: "-50px" }}
                transition={{ duration: 0.5, delay: i * 0.1 }}
                className="group p-8 rounded-3xl bg-slate-50 dark:bg-white/5 border border-slate-100 dark:border-white/10 hover:border-amber-500/50 dark:hover:border-amber-500/50 transition-colors"
              >
                <div className="w-14 h-14 rounded-2xl bg-white dark:bg-white/10 shadow-sm flex items-center justify-center mb-6 text-amber-600 dark:text-amber-400 group-hover:scale-110 transition-transform">
                  {srv.icon}
                </div>
                <h3 className="text-xl font-bold mb-3">{srv.title}</h3>
                <p className="text-sm text-slate-600 dark:text-slate-400 leading-relaxed">
                  {srv.desc}
                </p>
              </motion.div>
            ))}
          </div>
        </div>
      </section>

      {/* 3. BEFORE & AFTER SLIDER (The Proof) */}
      <section className="py-24 bg-[#F8F9FA] dark:bg-[#0B0C10] overflow-hidden" id="portfolio">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex flex-col lg:flex-row justify-between items-end mb-12 gap-6">
             <div className="max-w-2xl">
               <h2 className="text-3xl md:text-5xl font-black mb-6">The Alphadigify Difference</h2>
               <p className="text-lg text-slate-600 dark:text-slate-400">
                 Drag the slider to see how we transform generic product imagery into high-end, conversion-focused brand assets.
               </p>
             </div>
             <Button variant="ghost" className="hidden lg:flex items-center space-x-2 font-bold hover:bg-transparent hover:text-amber-500">
               <span>View Full Portfolio</span> <MoveRight className="w-5 h-5" />
             </Button>
          </div>

          <motion.div 
            initial={{ opacity: 0, scale: 0.95 }}
            whileInView={{ opacity: 1, scale: 1 }}
            viewport={{ once: true }}
            transition={{ duration: 0.6 }}
            className="relative w-full aspect-[16/9] md:aspect-[21/9] rounded-3xl overflow-hidden shadow-2xl bg-slate-900 group select-none"
          >
            {/* "Before" Image (Generic/Ugly) */}
            <div className="absolute inset-0 w-full h-full bg-[url('https://images.unsplash.com/photo-1542291026-7eec264c27ff?auto=format&fit=crop&w=1600&q=80')] bg-cover bg-center grayscale opacity-80" />

            {/* "After" Image (Designed/Premium) - Clipped */}
            <div 
              className="absolute inset-0 w-full h-full bg-[url('https://images.unsplash.com/photo-1542291026-7eec264c27ff?auto=format&fit=crop&w=1600&q=80')] bg-cover bg-center transition-all duration-75"
              style={{ clipPath: `polygon(0 0, ${sliderPosition}% 0, ${sliderPosition}% 100%, 0 100%)`, filter: "contrast(1.2) saturate(1.3)" }}
            >
              {/* Fake UI Overlay to make it look like a designed ad */}
              <div className="absolute inset-0 bg-gradient-to-r from-red-600/50 to-transparent mix-blend-multiply" />
              <div className="absolute bottom-10 left-10 text-white">
                <h3 className="text-5xl font-black italic uppercase tracking-tighter">Velocity Pro</h3>
                <p className="text-xl font-bold mt-2 tracking-widest">RUN FASTER. GO FURTHER.</p>
              </div>
            </div>

            {/* Slider Handle */}
            <div 
              className="absolute top-0 bottom-0 w-1 bg-white cursor-ew-resize z-20 flex items-center justify-center transition-all duration-75 shadow-[0_0_15px_rgba(0,0,0,0.5)]"
              style={{ left: `calc(${sliderPosition}% - 2px)` }}
            >
              <div className="w-8 h-8 bg-white rounded-full shadow-lg flex items-center justify-center text-slate-900 text-[10px] font-bold">
                ◄ ►
              </div>
            </div>

            {/* Invisible Range Input for accessibility and easy drag */}
            <input 
              type="range" 
              min="0" 
              max="100" 
              value={sliderPosition} 
              onChange={(e) => setSliderPosition(Number(e.target.value))}
              className="absolute inset-0 w-full h-full opacity-0 cursor-ew-resize z-30"
            />

            {/* Labels */}
            <div className="absolute top-6 left-6 bg-black/50 backdrop-blur text-white text-xs font-bold px-3 py-1.5 rounded-full z-10 uppercase tracking-wider">After Design</div>
            <div className="absolute top-6 right-6 bg-black/50 backdrop-blur text-white text-xs font-bold px-3 py-1.5 rounded-full z-10 uppercase tracking-wider">Before</div>
          </motion.div>

          <div className="mt-8 flex justify-center lg:hidden">
             <Button variant="ghost" className="flex items-center space-x-2 font-bold hover:bg-transparent hover:text-amber-500">
               <span>View Full Portfolio</span> <MoveRight className="w-5 h-5" />
             </Button>
          </div>
        </div>
      </section>

      {/* 4. THE PROCESS */}
      <section className="py-24 bg-white dark:bg-[#121318]">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="text-center mb-16 lg:mb-24">
            <h2 className="text-3xl md:text-5xl font-black mb-6">Our Process</h2>
            <p className="text-lg text-slate-600 dark:text-slate-400 max-w-2xl mx-auto">
              We leave nothing to chance. A structured, transparent pipeline from concept to final pixel.
            </p>
          </div>

          <div className="grid md:grid-cols-4 gap-8">
            {PROCESS_STEPS.map((step, i) => (
              <motion.div 
                key={i}
                initial={{ opacity: 0, scale: 0.9 }}
                whileInView={{ opacity: 1, scale: 1 }}
                viewport={{ once: true }}
                transition={{ duration: 0.4, delay: i * 0.15 }}
                className="relative"
              >
                {/* Connecting Line */}
                {i < PROCESS_STEPS.length - 1 && (
                  <div className="hidden md:block absolute top-10 left-1/2 w-full h-px bg-slate-200 dark:bg-white/10" />
                )}

                <div className="bg-slate-50 dark:bg-white/5 border border-slate-200 dark:border-white/10 w-20 h-20 rounded-full flex items-center justify-center text-2xl font-black text-slate-300 dark:text-white/20 mb-8 relative z-10 mx-auto">
                  {step.step}
                </div>

                <div className="text-center">
                  <h3 className="text-xl font-bold mb-3">{step.title}</h3>
                  <p className="text-sm text-slate-600 dark:text-slate-400">{step.desc}</p>
                </div>
              </motion.div>
            ))}
          </div>
        </div>
      </section>

      {/* 5. CTA */}
      <section className="py-24 relative overflow-hidden bg-slate-900 text-white">
        <div className="absolute inset-0 bg-[url('https://images.unsplash.com/photo-1618005182384-a83a8bd57fbe?auto=format&fit=crop&w=2000&q=80')] bg-cover bg-center opacity-10 mix-blend-luminosity" />
        <div className="max-w-4xl mx-auto px-4 text-center relative z-10">
          <h2 className="text-4xl md:text-6xl font-black mb-8">Ready to upgrade your visuals?</h2>
          <p className="text-xl text-slate-300 mb-10 max-w-2xl mx-auto">
            Stop losing sales to competitors with better branding. Let our design team engineer visuals that demand attention.
          </p>
          <Link href="/contact">
            <Button size="lg" className="bg-amber-500 text-black hover:bg-amber-400 font-bold h-16 px-10 text-lg rounded-full">
              Get Your Custom Quote <ArrowRight className="ml-2 h-5 w-5" />
            </Button>
          </Link>
        </div>
      </section>

      <Footer />

      {/* Global Styles for Animations */}
      <style dangerouslySetInnerHTML={{__html: `
        @keyframes marquee-vertical {
          0% { transform: translateY(0); }
          100% { transform: translateY(-50%); }
        }
        @keyframes marquee-vertical-reverse {
          0% { transform: translateY(-50%); }
          100% { transform: translateY(0); }
        }
        .animate-marquee-vertical {
          animation: marquee-vertical 25s linear infinite;
        }
        .animate-marquee-vertical-reverse {
          animation: marquee-vertical-reverse 25s linear infinite;
        }
      `}} />
    </main>
  );
}

